#define GAMMA 1.4f
#define iterations 2000
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#ifndef BLOCK_SIZE_0
#define BLOCK_SIZE_0 192
#endif
#ifndef BLOCK_SIZE_1
