            float momentum_nb_z = variables[nb + (VAR_MOMENTUM+2)*nelr];
            float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];

            float velocity_nb_x = momentum_nb_x / density_nb;
            float velocity_nb_y = momentum_nb_y / density_nb;
            float velocity_nb_z = momentum_nb_z / density_nb;

            float speed_sqd_nb = velocity_nb_x*velocity_nb_x + velocity_nb_y*velocity_nb_y + velocity_nb_z*velocity_nb_z;
            float pressure_nb = (GAMMA-1.0f)*(density_energy_nb - 0.5f*density_nb*speed_sqd_nb);
            float speed_of_sound_nb = sqrtf(GAMMA*pressure_nb/density_nb);

            float de_p_nb = density_energy_nb + pressure_nb;
            float fc_nb_mx_x = velocity_nb_x*momentum_nb_x + pressure_nb;
            float fc_nb_mx_y = velocity_nb_x*momentum_nb_y;
            float fc_nb_mx_z = velocity_nb_x*momentum_nb_z;

            float fc_nb_my_x = fc_nb_mx_y;
            float fc_nb_my_y = velocity_nb_y*momentum_nb_y + pressure_nb;
            float fc_nb_my_z = velocity_nb_y*momentum_nb_z;

            float fc_nb mz_x = fc_nb_mx_z;
            float fc_nb mz_y = fc_nb_my_z;
            float fc_nb mz_z = velocity_nb_z*momentum_nb_z + pressure_nb;

            float fc_nb_de_x = velocity_nb_x*de_p_nb;
            float fc_nb_de_y = velocity_nb_y*de_p_nb;
            float fc_nb_de_z = velocity_nb_z*de_p_nb;

            factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density += factor*(density_i-density_nb);
            flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
            flux_i_mx += factor*(momentum_i_x-momentum_nb_x);
            flux_i_my += factor*(momentum_i_y-momentum_nb_y);
            flux_i mz += factor*(momentum_i_z-momentum_nb_z);

            factor = 0.5f*normal_x;
            flux_i_density += factor*(momentum_nb_x+momentum_i_x);
            flux_i_density_energy += factor*(fc_nb_de_x+fc_i_de_x);
            flux_i_mx += factor*(fc_nb_mx_x+fc_i_mx_x);
            flux_i_my += factor*(fc_nb_my_x+fc_i_my_x);
            flux_i mz += factor*(fc_nb mz_x+fc_i mz_x);

            factor = 0.5f*normal_y;
            flux_i_density += factor*(momentum_nb_y+momentum_i_y);
            flux_i_density_energy += factor*(fc_nb_de_y+fc_i_de_y);
            flux_i_mx += factor*(fc_nb_mx_y+fc_i_mx_y);
            flux_i_my += factor*(fc_nb_my_y+fc_i_my_y);
            flux_i mz += factor*(fc_nb mz_y+fc_i mz_y);

            factor = 0.5f*normal_z;
            flux_i_density += factor*(momentum_nb_z+momentum_i_z);
            flux_i_density_energy += factor*(fc_nb_de_z+fc_i_de_z);
            flux_i_mx += factor*(fc_nb_mx_z+fc_i_mx_z);
            flux_i_my += factor*(fc_nb_my_z+fc_i_my_z);
            flux_i mz += factor*(fc_nb mz_z+fc_i mz_z);
        }
        else if(nb == -1) {
            flux_i_mx += normal_x*pressure_i;
            flux_i_my += normal_y*pressure_i;
            flux_i mz += normal_z*pressure_i;
        }
        else if(nb == -2) {
            factor = 0.5f*normal_x;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i_x);
            flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].x+fc_i_de_x);
            flux_i_mx += factor*(ff_flux_contribution_momentum_x[0].x + fc_i_mx_x);
            flux_i_my += factor*(ff_flux_contribution_momentum_y[0].x + fc_i_my_x);
            flux_i mz += factor*(ff_flux_contribution_momentum_z[0].x + fc_i mz_x);

            factor = 0.5f*normal_y;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i_y);
            flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].y+fc_i_de_y);
            flux_i_mx += factor*(ff_flux_contribution_momentum_x[0].y + fc_i_mx_y);
            flux_i_my += factor*(ff_flux_contribution_momentum_y[0].y + fc_i_my_y);
            flux_i mz += factor*(ff_flux_contribution_momentum_z[0].y + fc_i mz_y);

            factor = 0.5f*normal_z;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i_z);
            flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].z+fc_i_de_z);
            flux_i_mx += factor*(ff_flux_contribution_momentum_x[0].z + fc_i_mx_z);
            flux_i_my += factor*(ff_flux_contribution_momentum_y[0].z + fc_i_my_z);
            flux_i mz += factor*(ff_flux_contribution_momentum_z[0].z + fc_i mz_z);
        }
    }

    fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
    fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_mx;
    fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_my;
    fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i mz;
    fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
}

__kernel void cuda_time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes) {
    const int i = get_global_id(0);
    if (i < nelr) {
        float factor = step_factors[i]/(float)(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];	
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];	
    }
}

#define GAMMA 1.4f
#define iterations 2000
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#ifndef BLOCK_SIZE_0
#define BLOCK_SIZE_0 192
#endif
#ifndef BLOCK_SIZE_1
#define BLOCK_SIZE_1 192
#endif
#ifndef BLOCK_SIZE_2
#define BLOCK_SIZE_2 192
#endif
#ifndef BLOCK_SIZE_3
#define BLOCK_SIZE_3 192
#endif
#ifndef BLOCK_SIZE_4
#define BLOCK_SIZE_4 192
#endif

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

__kernel void kernel_initialize_variables(float* variables, const float* ff_variable, int nelr) {
    int i = get_global_id(0);
    if (i < nelr) {
        for(int j = 0; j < NVAR; j++) {
            variables[i + j*nelr] = ff_variable[j];
        }
    }
}

__kernel void kernel_compute_step_factor(float* variables, float* areas, float* step_factors, int nelr) {
    int i = get_global_id(0);
    if (i < nelr) {
        float density = variables[i + VAR_DENSITY*nelr];
        float momentum_x = variables[i + (VAR_MOMENTUM+0)*nelr];
        float momentum_y = variables[i + (VAR_MOMENTUM+1)*nelr];
        float momentum_z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

        float velocity_x = momentum_x / density;
        float velocity_y = momentum_y / density;
        float velocity_z = momentum_z / density;

        float speed_sqd = velocity_x*velocity_x + velocity_y*velocity_y + velocity_z*velocity_z;
        float pressure = (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
        float speed_of_sound = sqrtf(GAMMA * pressure / density);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

__kernel void kernel_compute_flux(int* elements_surrounding_elements, float* normals, float* variables, const float* ff_variable, 
                                  float* fluxes, const float* ff_flux_contribution_density_energy,
                                  const float* ff_flux_contribution_momentum_x,
                                  const float* ff_flux_contribution_momentum_y,
                                  const float* ff_flux_contribution_momentum_z, int nelr) {
    int i = get_global_id(0);
    if (i >= nelr) return;

    const float smoothing_coefficient = 0.2f;

    float density_i = variables[i + VAR_DENSITY*nelr];
    float momentum_i_x = variables[i + (VAR_MOMENTUM+0)*nelr];
    float momentum_i_y = variables[i + (VAR_MOMENTUM+1)*nelr];
    float momentum_i_z = variables[i + (VAR_MOMENTUM+2)*nelr];
    float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

    float velocity_i_x = momentum_i_x / density_i;
    float velocity_i_y = momentum_i_y / density_i;
    float velocity_i_z = momentum_i_z / density_i;

    float speed_sqd_i = velocity_i_x*velocity_i_x + velocity_i_y*velocity_i_y + velocity_i_z*velocity_i_z;
    float speed_i = sqrtf(speed_sqd_i);
    float pressure_i = (GAMMA - 1.0f) * (density_energy_i - 0.5f * density_i * speed_sqd_i);
    float speed_of_sound_i = sqrtf(GAMMA * pressure_i / density_i);

    float fc_i_momentum_x_x = velocity_i_x*momentum_i_x + pressure_i;
    float fc_i_momentum_x_y = velocity_i_x*momentum_i_y;
    float fc_i_momentum_x_z = velocity_i_x*momentum_i_z;

    float fc_i_momentum_y_x = fc_i_momentum_x_y;
    float fc_i_momentum_y_y = velocity_i_y*momentum_i_y + pressure_i;
    float fc_i_momentum_y_z = velocity_i_y*momentum_i_z;

    float fc_i_momentum_z_x = fc_i_momentum_x_z;
    float fc_i_momentum_z_y = fc_i_momentum_y_z;
    float fc_i_momentum_z_z = velocity_i_z*momentum_i_z + pressure_i;

    float de_p_i = density_energy_i + pressure_i;
    float fc_i_density_energy_x = velocity_i_x*de_p_i;
    float fc_i_density_energy_y = velocity_i_y*de_p_i;
    float fc_i_density_energy_z = velocity_i_z*de_p_i;

    float flux_i_density = 0.0f;
    float flux_i_momentum_x = 0.0f;
    float flux_i_momentum_y = 0.0f;
    float flux_i_momentum_z = 0.0f;
    float flux_i_density_energy = 0.0f;

    // Access constants as arrays of floats (since float3 struct is 3 floats)
    // ff_flux_contribution_momentum_x[0].x is at index 0, .y at 1, .z at 2?
    // The host passes pointer to struct {x,y,z}. In memory it's 3 floats.
    // So x=0, y=1, z=2.
    float ff_fc_de_x = ff_flux_contribution_density_energy[0];
    float ff_fc_de_y = ff_flux_contribution_density_energy[1];
    float ff_fc_de_z = ff_flux_contribution_density_energy[2];

    float ff_fc_mx_x = ff_flux_contribution_momentum_x[0];
    float ff_fc_mx_y = ff_flux_contribution_momentum_x[1];
    float ff_fc_mx_z = ff_flux_contribution_momentum_x[2];

    float ff_fc_my_x = ff_flux_contribution_momentum_y[0];
    float ff_fc_my_y = ff_flux_contribution_momentum_y[1];
    float ff_fc_my_z = ff_flux_contribution_momentum_y[2];

    float ff_fc mz_x = ff_flux_contribution_momentum_z[0];
    float ff_fc mz_y = ff_flux_contribution_momentum_z[1];
    float ff_fc mz_z = ff_flux_contribution_momentum_z[2];

    for(int j = 0; j < NNB; j++) {
        int nb = elements_surrounding_elements[i + j*nelr];
        float normal_x = normals[i + (j + 0*NNB)*nelr];
        float normal_y = normals[i + (j + 1*NNB)*nelr];
        float normal_z = normals[i + (j + 2*NNB)*nelr];
        float normal_len = sqrtf(normal_x*normal_x + normal_y*normal_y + normal_z*normal_z);

        if(nb >= 0) {
            float density_nb = variables[nb + VAR_DENSITY*nelr];
            float momentum_nb_x = variables[nb + (VAR_MOMENTUM+0)*nelr];
            float momentum_nb_y = variables[nb + (VAR_MOMENTUM+1)*nelr];
            float momentum_nb_z = variables[nb + (VAR_MOMENTUM+2)*nelr];
            float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];

            float velocity_nb_x = momentum_nb_x / density_nb;
            float velocity_nb_y = momentum_nb_y / density_nb;
            float velocity_nb_z = momentum_nb_z / density_nb;

            float speed_sqd_nb = velocity_nb_x*velocity_nb_x + velocity_nb_y*velocity_nb_y + velocity_nb_z*velocity_nb_z;
            float pressure_nb = (GAMMA - 1.0f) * (density_energy_nb - 0.5f * density_nb * speed_sqd_nb);
            float speed_of_sound_nb = sqrtf(GAMMA * pressure_nb / density_nb);

            float fc_nb_momentum_x_x = velocity_nb_x*momentum_nb_x + pressure_nb;
            float fc_nb_momentum_x_y = velocity_nb_x*momentum_nb_y;
            float fc_nb_momentum_x_z = velocity_nb_x*momentum_nb_z;

            float fc_nb_momentum_y_x = fc_nb_momentum_x_y;
            float fc_nb_momentum_y_y = velocity_nb_y*momentum_nb_y + pressure_nb;
            float fc_nb_momentum_y_z = velocity_nb_y*momentum_nb_z;

            float fc_nb_momentum_z_x = fc_nb_momentum_x_z;
            float fc_nb_momentum_z_y = fc_nb_momentum_y_z;
            float fc_nb_momentum_z_z = velocity_nb_z*momentum_nb_z + pressure_nb;

            float de_p_nb = density_energy_nb + pressure_nb;
            float fc_nb_density_energy_x = velocity_nb_x*de_p_nb;
            float fc_nb_density_energy_y = velocity_nb_y*de_p_nb;
            float fc_nb_density_energy_z = velocity_nb_z*de_p_nb;

            float factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
            flux_i_density += factor*(density_i-density_nb);
            flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
            flux_i_momentum_x += factor*(momentum_i_x-momentum_nb_x);
            flux_i_momentum_y += factor*(momentum_i_y-momentum_nb_y);
            flux_i_momentum_z += factor*(momentum_i_z-momentum_nb_z);

            factor = 0.5f*normal_x;
            flux_i_density += factor*(momentum_nb_x+momentum_i_x);
            flux_i_density_energy += factor*(fc_nb_density_energy_x+fc_i_density_energy_x);
            flux_i_momentum_x += factor*(fc_nb_momentum_x_x+fc_i_momentum_x_x);
            flux_i_momentum_y += factor*(fc_nb_momentum_y_x+fc_i_momentum_y_x);
            flux_i_momentum_z += factor*(fc_nb_momentum_z_x+fc_i_momentum_z_x);

            factor = 0.5f*normal_y;
            flux_i_density += factor*(momentum_nb_y+momentum_i_y);
            flux_i_density_energy += factor*(fc_nb_density_energy_y+fc_i_density_energy_y);
            flux_i_momentum_x += factor*(fc_nb_momentum_x_y+fc_i_momentum_x_y);
            flux_i_momentum_y += factor*(fc_nb_momentum_y_y+fc_i_momentum_y_y);
            flux_i_momentum_z += factor*(fc_nb_momentum_z_y+fc_i_momentum_z_y);

            factor = 0.5f*normal_z;
            flux_i_density += factor*(momentum_nb_z+momentum_i_z);
            flux_i_density_energy += factor*(fc_nb_density_energy_z+fc_i_density_energy_z);
            flux_i_momentum_x += factor*(fc_nb_momentum_x_z+fc_i_momentum_x_z);
            flux_i_momentum_y += factor*(fc_nb_momentum_y_z+fc_i_momentum_y_z);
            flux_i_momentum_z += factor*(fc_nb_momentum_z_z+fc_i_momentum_z_z);
        }
        else if(nb == -1) {
            flux_i_momentum_x += normal_x*pressure_i;
            flux_i_momentum_y += normal_y*pressure_i;
            flux_i_momentum_z += normal_z*pressure_i;
        }
        else if(nb == -2) {
            float factor = 0.5f*normal_x;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i_x);
            flux_i_density_energy += factor*(ff_fc_de_x+fc_i_density_energy_x);
            flux_i_momentum_x += factor*(ff_fc_mx_x + fc_i_momentum_x_x);
            flux_i_momentum_y += factor*(ff_fc_my_x + fc_i_momentum_y_x);
            flux_i_momentum_z += factor*(ff_fc mz_x + fc_i_momentum_z_x);

            factor = 0.5f*normal_y;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i_y);
            flux_i_density_energy += factor*(ff_fc_de_y+fc_i_density_energy_y);
            flux_i_momentum_x += factor*(ff_fc_mx_y + fc_i_momentum_x_y);
            flux_i_momentum_y += factor*(ff_fc_my_y + fc_i_momentum_y_y);
            flux_i_momentum_z += factor*(ff_fc mz_y + fc_i_momentum_z_y);

            factor = 0.5f*normal_z;
            flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i_z);
            flux_i_density_energy += factor*(ff_fc_de_z+fc_i_density_energy_z);
            flux_i_momentum_x += factor*(ff_fc_mx_z + fc_i_momentum_x_z);
            flux_i_momentum_y += factor*(ff_fc_my_z + fc_i_momentum_y_z);
            flux_i_momentum_z += factor*(ff_fc mz_z + fc_i_momentum_z_z);
        }
    }

    fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
    fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum_x;
    fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum_y;
    fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum_z;
    fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
}

__kernel void kernel_time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes) {
    int i = get_global_id(0);
    if (i < nelr) {
        float factor = step_factors[i] / (float)(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
    }
}

#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

typedef struct{
    float x;
    float y;
    float z;
} float3;

__kernel void cuda_initialize_variables(__global float* variables, __global const float* ff_variable, int nelr)
{
    const int i = get_global_id(0);
    if (i < nelr) {
        for(int j = 0; j < NVAR; j++)
            variables[i + j*nelr] = ff_variable[j];
    }
}

__kernel void cuda_compute_step_factor(__global const float* variables, __global const float* areas, __global float* step_factors, int nelr)
{
    const int i = get_global_id(0);
    if (i >= nelr) return;

    float density = variables[i + VAR_DENSITY*nelr];
    float3 momentum;
    momentum.x = variables[i + (VAR_MOMENTUM+0)*nelr];
    momentum.y = variables[i + (VAR_MOMENTUM+1)*nelr];
    momentum.z = variables[i + (VAR_MOMENTUM+2)*nelr];

    float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

    float3 velocity;
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;

    float speed_sqd = velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
    float pressure = (GAMMA-1.0f)*(density_energy - 0.5f*density*speed_sqd);
    float speed_of_sound = sqrtf(GAMMA*pressure/density);

    step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
}

__kernel void cuda_compute_flux(__global const int* elements_surrounding_elements, __global const float* normals, __global const float* variables, __global const float* ff_variable, __global float* fluxes, __global const float3* ff_flux_contribution_density_energy, __global const float3* ff_flux_contribution_momentum_x, __global const float3* ff_flux_contribution_momentum_y, __global const float3* ff_flux_contribution_momentum_z, int nelr)
{
    const float smoothing_coefficient = 0.2f;
    const int i = get_global_id(0);
    if (i >= nelr) return;

    int j, nb;
    float3 normal; 
    float normal_len;
    float factor;

    float density_i = variables[i + VAR_DENSITY*nelr];
    float3 momentum_i;
    momentum_i.x = variables[i + (VAR_MOMENTUM+0)*nelr];
    momentum_i.y = variables[i + (VAR_MOMENTUM+1)*nelr];
    momentum_i.z = variables[i + (VAR_MOMENTUM+2)*nelr];

    float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

    float3 velocity_i;
    velocity_i.x = momentum_i.x / density_i;
    velocity_i.y = momentum_i.y / density_i;
    velocity_i.z = momentum_i.z / density_i;

    float speed_sqd_i = velocity_i.x*velocity_i.x + velocity_i.y*velocity_i.y + velocity_i.z*velocity_i.z;
    float speed_i = sqrtf(speed_sqd_i);
    float pressure_i = (GAMMA-1.0f)*(density_energy_i - 0.5f*density_i*speed_sqd_i);
    float speed_of_sound_i = sqrtf(GAMMA*pressure_i/density_i);

    float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
    float3 flux_contribution_i_density_energy;

    float de_p_i = density_energy_i + pressure_i;
    flux_contribution_i_momentum_x.x = velocity_i.x*momentum_i.x + pressure_i;
    flux_contribution_i_momentum_x.y = velocity_i.x*momentum_i.y;
    flux_contribution_i_momentum_x.z = velocity_i.x*momentum_i.z;

    flux_contribution_i_momentum_y.x = flux_contribution_i_momentum_x.y;
    flux_contribution_i_momentum_y.y = velocity_i.y*momentum_i.y + pressure_i;
    flux_contribution_i_momentum_y.z = velocity_i.y*momentum_i.z;

    flux_contribution_i_momentum_z.x = flux_contribution_i_momentum_x.z;
    flux_contribution_i_momentum_z.y = flux_contribution_i_momentum_y.z;
    flux_contribution_i_momentum_z.z = velocity_i.z*momentum_i.z + pressure_i;

    flux_contribution_i_density_energy.x = velocity_i.x*de_p_i;
    flux_contribution_i_density_energy.y = velocity_i.y*de_p_i;
    flux_contribution_i_density_energy.z = velocity_i.z*de_p_i;

    float flux_i_density = 0.0f;
    float3 flux_i_momentum;
    flux_i_momentum.x = 0.0f;
    flux_i_momentum.y = 0.0f;
    flux_i_momentum.z = 0.0f;
    float flux_i_density_energy = 0.0f;

    float3 velocity_nb;
    float density_nb, density_energy_nb;
    float3 momentum_nb;
    float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
    float3 flux_contribution_nb_density_energy;
    float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

    for(j = 0; j < NNB; j++)
    {
        nb = elements_surrounding_elements[i + j*nelr];
        normal.x = normals[i + (j + 0*NNB)*nelr];
        normal.y = normals[i + (j + 1*NNB)*nelr];
        normal.z = normals[i + (j + 2*NNB)*nelr];
        normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

        if(nb >= 0) 
        {
            density_nb = variables[nb + VAR_DENSITY*nelr];
            momentum_nb.x = variables[nb + (VAR_MOMENTUM+0)*nelr];
            momentum_nb.y = variables[nb + (VAR_MOMENTUM+1)*nelr];
            momentum_nb.z = variables[nb + (VAR_MOMENTUM+2)*nelr];
            density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];

            velocity_nb.x = momentum_nb.x / density_nb;
            velocity_nb.y = momentum_nb.y / density_nb;
            velocity_nb.z = momentum_nb.z / density_nb;

            speed_sqd_nb = velocity_nb.x*velocity_nb.x + velocity_nb.y*velocity_nb.y + velocity_nb.z*velocity_nb.z;
