    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const int * const in, int * const out, const int sizeX, const int sizeY, const int winSteps, int local_x, int group_x, int group_y) {
      FDWT53Column<CHECK_LOADS> column;
      FDWT53Column<CHECK_LOADS> boundaryColumn;
      const int firstY = group_y * WIN_SIZE_Y * winSteps;
      initColumn(column, in, sizeX, sizeY, local_x, firstY, local_x, group_y, group_x);
      boundaryColumn.clear();
      if(local_x < 3) {
        const int colId = local_x + ((local_x == 0) ? WIN_SIZE_X : -3);
        initColumn(boundaryColumn, in, sizeX, sizeY, colId, firstY, local_x, group_y, group_x);
      }
      const int outColumnIndex = parityIdx(local_x, WIN_SIZE_X);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
      const int outputFirstX = group_x * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<int, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, outputFirstX, firstY);

      for(int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform(column, in);
        if(local_x < 3) { 
          loadAndVerticallyTransform(boundaryColumn, in); 
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        buffer.forEachHorizontalOdd(2, WIN_SIZE_Y, Forward53Predict(), local_x);
        barrier(CLK_LOCAL_MEM_FENCE);
        buffer.forEachHorizontalEven(2, WIN_SIZE_Y, Forward53Update(), local_x);
        barrier(CLK_LOCAL_MEM_FENCE);
        for(int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
          writer.writeLowInto(out, buffer[outColumnOffset + r * STRIDE]);
          writer.writeHighInto(out, buffer[outColumnOffset + (r+1) * STRIDE]);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
      }
    }

  public:
    static void run(const int * const in, int * const out, const int sx, const int sy, const int steps, int local_x, int group_x, int group_y) {
      FDWT53<WIN_SIZE_X, WIN_SIZE_Y> fdwt53;
      const int maxX = (group_x + 1) * WIN_SIZE_X + 1;
      const int maxY = (group_y + 1) * WIN_SIZE_Y * steps + 1;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        fdwt53.transform<true, true>(in, out, sx, sy, steps, local_x, group_x, group_y);
      } else if(atRightBoudary) {
        fdwt53.transform<false, true>(in, out, sx, sy, steps, local_x, group_x, group_y);
      } else {
        fdwt53.transform<false, false>(in, out, sx, sy, steps, local_x, group_x, group_y);
      }
    }
};

