template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT97 {
  private:
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> FDWT97Buffer;
    FDWT97Buffer buffer;
    enum { STRIDE = FDWT97Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct FDWT97ColumnLoadingInfo {
      VerticalDWTPixelLoader<float, CHECKED> loader;
      int offset;
    };

    void horizontalFDWT97(const int lines, const int firstLine, int local_x) {
      barrier(CLK_LOCAL_MEM_FENCE);
      AddScaledSum func1 = {f97Predict1};
      AddScaledSum func2 = {f97Update1};
      AddScaledSum func3 = {f97Predict2};
      AddScaledSum func4 = {f97Update2};
      buffer.forEachHorizontalOdd(firstLine, lines, func1, local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalEven(firstLine, lines, func2, local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalOdd(firstLine, lines, func3, local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalEven(firstLine, lines, func4, local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.scaleHorizontal(scale97Div, scale97Mul, firstLine, lines, local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
    }

    template <bool CHECKED>
    void initColumn(FDWT97ColumnLoadingInfo<CHECKED> & column, const int columnIndex, const float * const input, 
                    const int sizeX, const int sizeY, const int firstY, int local_x, int group_y, int group_x) {
      column.offset = buffer.getColumnOffset(columnIndex);
      const int firstX = group_x * WIN_SIZE_X + columnIndex;
      if(group_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 3 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 5 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 6 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadFrom(input);
        column.loader.init(sizeX, sizeY, firstX, firstY + 3);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 4);
        for(int i = 0; i < 7; i++) {
          buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const float * const input, FDWT97ColumnLoadingInfo<CHECKED> & column) {
      for(int i = 7; i < (7 + WIN_SIZE_Y); i++) {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const float * const in, float * const out, const int sizeX, const int sizeY, const int winSteps, int local_x, int group_x, int group_y) {
      FDWT97ColumnLoadingInfo<CHECK_LOADS> loadedColumn;
      FDWT97ColumnLoadingInfo<CHECK_LOADS> boundaryColumn;
      const int firstY = group_y * WIN_SIZE_Y * winSteps;
      initColumn(loadedColumn, local_x, in, sizeX, sizeY, firstY, local_x, group_y, group_x);
      boundaryColumn.offset = 0;
      boundaryColumn.loader.clear();
      if(local_x < 7) {
        const int colId = local_x + ((local_x < 3) ? WIN_SIZE_X : -7);
        initColumn(boundaryColumn, colId, in, sizeX, sizeY, firstY, local_x, group_y, group_x);
      }
      horizontalFDWT97(7, 0, local_x);
      const int outColumnIndex = parityIdx(local_x, WIN_SIZE_X);
      const int firstX = group_x * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<float, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, firstX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);

      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, loadedColumn);
        if(local_x < 7) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalFDWT97(WIN_SIZE_Y, 7, local_x);
        float last7Lines[7];
        for(int i = 0; i < 7; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }
        AddScaledSum func1 = {f97Predict1};
        AddScaledSum func2 = {f97Update1};
        AddScaledSum func3 = {f97Predict2};
        AddScaledSum func4 = {f97Update2};
        buffer.forEachVerticalOdd(outColumnOffset, func1, 0);
        buffer.forEachVerticalEven(outColumnOffset, func2, 0);
        buffer.forEachVerticalOdd(outColumnOffset, func3, 0);
        buffer.forEachVerticalEven(outColumnOffset, func4, 0);
        for(int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
          const int index = outColumnOffset + i * STRIDE;
          writer.writeLowInto(out, buffer[index] * scale97Div);
          writer.writeHighInto(out, buffer[index + STRIDE] * scale97Mul);
        }
        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
      }
    }

  public:
    static void run(const float * const input, float * const output, const int sx, const int sy, const int steps, int local_x, int group_x, int group_y) {
      FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
      const int maxX = (group_x + 1) * WIN_SIZE_X + 3;
      const int maxY = (group_y + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        fdwt97.transform<true, true>(input, output, sx, sy, steps, local_x, group_x, group_y);
      } else if(atRightBoudary) {
        fdwt97.transform<false, true>(input, output, sx, sy, steps, local_x, group_x, group_y);
      } else {
        fdwt97.transform<false, false>(input, output, sx, sy, steps, local_x, group_x, group_y);
      }
    }
};

