    FDWT97<WIN_SX, WIN_SY>::run(input, output, sx, sy, steps, get_local_id(0), get_group_id(0), get_group_id(1));
}

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class RDWT53 {
  private: 
    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> RDWT53Buffer;
    RDWT53Buffer buffer;
    enum { STRIDE = RDWT53Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct RDWT53Column {
      VerticalDWTBandLoader<int, CHECKED> loader;
      int offset;
      void clear() {
        offset = 0;
        loader.clear();
      }
    };

    void horizontalTransform(const int lines, const int firstLine, int local_x) {
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalEven(firstLine, lines, Reverse53Update(), local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalOdd(firstLine, lines, Reverse53Predict(), local_x);
      barrier(CLK_LOCAL_MEM_FENCE);
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const int * const input, RDWT53Column<CHECKED> & col) {
      for(int i = 3; i < (3 + WIN_SIZE_Y); i += 2) {
        buffer[col.offset + i * STRIDE] = col.loader.loadLowFrom(input);
        buffer[col.offset + (i + 1) * STRIDE] = col.loader.loadHighFrom(input);
      }
    }

    template <bool CHECKED>
    void initColumn(const int columnX, const int * const input, const int sizeX, const int sizeY,
                    RDWT53Column<CHECKED> & column, const int firstY, int local_x, int group_y, int group_x) {
      const int firstX = group_x * WIN_SIZE_X + columnX;
      column.offset = buffer.getColumnOffset(columnX);
      if(group_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 1);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadHighFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadLowFrom(input);
        buffer[column.offset + 2 * STRIDE] = column.loader.loadHighFrom(input);
      }
    }

    template<bool CHECKED_LOADS, bool CHECKED_WRITES>
    void transform(const int * const in, int * const out, const int sizeX, const int sizeY, const int winSteps, int local_x, int group_x, int group_y) {
      RDWT53Column<CHECKED_LOADS> column, boundaryColumn;
      const int firstY = group_y * WIN_SIZE_Y * winSteps;
      boundaryColumn.clear();
      if(local_x < 3) {
        const int colId = local_x + ((local_x != 2) ? WIN_SIZE_X : -3);
        initColumn(colId, in, sizeX, sizeY, boundaryColumn, firstY, local_x, group_y, group_x);
      }
      initColumn(parityIdx(local_x, WIN_SIZE_X), in, sizeX, sizeY, column, firstY, local_x, group_y, group_x);
      horizontalTransform(3, 0, local_x);
      const int outX = group_x * WIN_SIZE_X + local_x;
      VerticalDWTPixelWriter<int, CHECKED_WRITES> writer;
      writer.init(sizeX, sizeY, outX, firstY);
      const int outputColumnOffset = buffer.getColumnOffset(local_x);

      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, column);
        if(local_x < 3) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalTransform(WIN_SIZE_Y, 3, local_x);
        int last3Lines[3];
        last3Lines[0] = buffer[outputColumnOffset + (WIN_SIZE_Y + 0) * STRIDE];
        last3Lines[1] = buffer[outputColumnOffset + (WIN_SIZE_Y + 1) * STRIDE];
        last3Lines[2] = buffer[outputColumnOffset + (WIN_SIZE_Y + 2) * STRIDE];
        buffer.forEachVerticalOdd(outputColumnOffset, Reverse53Update(), 0);
        buffer.forEachVerticalEven(outputColumnOffset, Reverse53Predict(), 0);
        for(int i = 1; i < (1 + WIN_SIZE_Y); i++) {
          writer.writeInto(out, buffer[outputColumnOffset + i * STRIDE]);
        }
        buffer[outputColumnOffset + 0 * STRIDE] = last3Lines[0];
        buffer[outputColumnOffset + 1 * STRIDE] = last3Lines[1];
        buffer[outputColumnOffset + 2 * STRIDE] = last3Lines[2];
        barrier(CLK_LOCAL_MEM_FENCE);
      }
    }

  public:
    static void run(const int * const input, int * const output, const int sx, const int sy, const int steps, int local_x, int group_x, int group_y) {
      RDWT53<WIN_SIZE_X, WIN_SIZE_Y> rdwt53;
      const int maxX = (group_x + 1) * WIN_SIZE_X + 1;
      const int maxY = (group_y + 1) * WIN_SIZE_Y * steps + 1;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;
      if(atBottomBoudary) {
        rdwt53.transform<true, true>(input, output, sx, sy, steps, local_x, group_x, group_y);
      } else if(atRightBoudary) {
        rdwt53.transform<false, true>(input, output, sx, sy, steps, local_x, group_x, group_y);
      } else {
        rdwt53.transform<false, false>(input, output, sx, sy, steps, local_x, group_x, group_y);
      }
    }
};

