#define IMUL(a, b) ((a)*(b))
#define DIVANDRND(a, b) ((((a) % (b)) != 0) ? ((a) / (b) + 1) : ((a) / (b)))

#define CTMIN(a,b) (((a) < (b)) ? (a) : (b))

const float f97Predict1 = -1.586134342f;   
const float f97Update1 = -0.05298011854f;  
const float f97Predict2 = 0.8829110762f;   
const float f97Update2 = 0.4435068522f;    

const float r97update2 = -f97Update2;    
const float r97predict2 = -f97Predict2;  
const float r97update1 = -f97Update1;    
const float r97Predict1 = -f97Predict1;  

const float scale97Mul = 1.23017410491400f;
const float scale97Div = 1.0f / scale97Mul;

const float forward53Predict = -0.5f;   
const float forward53Update = 0.25f;    

const float reverse53Update = -forward53Update;    
const float reverse53Predict = -forward53Predict;  

struct AddScaledSum {
    float scale;  
    void operator()(const float p, float & c, const float n) const {
      c += scale * (p + n);
    }
};

template <int THREADS>
int parityIdx() {
    return (get_local_id(0) * 2) - (THREADS - 1) * (get_local_id(0) / (THREADS / 2));
}

template <typename T>
T divRndUp(const T & n, const T & d) {
    return (n / d) + ((n % d) ? 1 : 0);
}

class DWTIO {
  protected:
    static void mirror(int & d, const int & sizeD) {
      if(d >= sizeD) {
        d = 2 * sizeD - 2 - d;
      } else if(d < 0) {
        d = -d;
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelIO : protected DWTIO {
  protected:
    int end;         
    int stride;      

    int initialize(const int sizeX, const int sizeY, int firstX, int firstY) {
      end = CHECKED ? (sizeY * sizeX + firstX) : 0;
      stride = sizeX;
      return firstX + sizeX * firstY;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelWriter : VerticalDWTPixelIO<T, CHECKED> {
  private:
    int next;   

  public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      if(firstX < sizeX) {
        next = this->initialize(sizeX, sizeY, firstX, firstY);
      } else {
        this->end = 0;
        this->stride = 0;
        next = 0;
      }
    }

    void writeInto(T * const output, const T & value) {
      if((!CHECKED) || (next != this->end)) {
        output[next] = value;
        next += this->stride;
      }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelLoader : protected VerticalDWTPixelIO<const T, CHECKED> {
  private:
    int last;  

  public:
    void init(const int sizeX, const int sizeY, int firstX, int firstY) {
      this->mirror(firstX, sizeX);
      last = this->initialize(sizeX, sizeY, firstX, firstY) - sizeX;
    }

    void clear() {
      this->end = 0;
      this->stride = 0;
      this->last = 0;
    }

    T loadFrom(const T * const input) {
      last += this->stride;
      if(CHECKED && (last == this->end)) {
        last -= 2 * this->stride;
        this->stride = -this->stride; 
      }
      return input[last];
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandIO : protected DWTIO {
  protected:
    int end;
    int strideHighToLow;
    int strideLowToHigh;

    int initialize(const int imageSizeX, const int imageSizeY, int firstX, int firstY) {
      int columnOffset = firstX / 2;
      int verticalStride;
      if(firstX & 1) {
        verticalStride = imageSizeX / 2;
        columnOffset += divRndUp(imageSizeX, 2) * divRndUp(imageSizeY, 2);
        strideLowToHigh = (imageSizeX * imageSizeY) / 2;
      } else {
        verticalStride = imageSizeX / 2 + (imageSizeX & 1);
        strideLowToHigh = divRndUp(imageSizeY, 2)  * imageSizeX;
      }
      strideHighToLow = verticalStride - strideLowToHigh;

      if(CHECKED) {
        end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
      } else {
        end = 0;
      }
      return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandLoader : public VerticalDWTBandIO<const T, CHECKED> {
  private:
    int last;  

    T updateAndLoad(const T * const input, const int & stride) {
      last += stride;
      if(CHECKED && (last == this->end)) {
        last -= (this->strideLowToHigh + this->strideHighToLow);
        const int temp = this->strideLowToHigh;
        this->strideLowToHigh = -this->strideHighToLow;
        this->strideHighToLow = -temp;
      }
      return input[last];
    }
  public:
    void init(const int imageSizeX, const int imageSizeY, int firstX, const int firstY) {
      this->mirror(firstX, imageSizeX);
      last = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
      last -= (firstY & 1) ? this->strideLowToHigh : this->strideHighToLow; 
    }

    void clear() {
      this->end = 0;
      this->strideHighToLow = 0;
      this->strideLowToHigh = 0;
      this->last = 0;
    }

    T loadLowFrom(const T * const input) {
      return updateAndLoad(input, this->strideHighToLow);
    }

    T loadHighFrom(const T * const input) {
      return updateAndLoad(input, this->strideLowToHigh);
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandWriter : public VerticalDWTBandIO<T, CHECKED> {
  private:
    int next;  

    int saveAndUpdate(T * const output, const T & item, const int & stride) {
      if((!CHECKED) || (next != this->end)) {
        output[next] = item;
        next += stride;
      } 
      return next;
    }
  public:
    void init(const int imageSizeX, const int imageSizeY, const int firstX, const int firstY) {
      if (firstX < imageSizeX) {
        next = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
      } else {
        clear();
      }
    }

    void clear() {
      this->end = 0;
      this->strideHighToLow = 0;
      this->strideLowToHigh = 0;
      this->next = 0;
    }

    int writeLowInto(T * const output, const T & primary) {
      return saveAndUpdate(output, primary, this->strideLowToHigh);
    }

    int writeHighInto(T * const output, const T & other) {
      return saveAndUpdate(output, other, this->strideHighToLow);
    }
};

template <typename T, int SIZE_X, int SIZE_Y, int BOUNDARY_X>
class TransformBuffer {
  public:
    enum {
      VERTICAL_STRIDE = BOUNDARY_X + (SIZE_X / 2)
    };

  private:
    enum {
      SHM_BANKS = 16,
      BUFFER_SIZE = VERTICAL_STRIDE * SIZE_Y,
      PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS),
      ODD_OFFSET = BUFFER_SIZE + PADDING,
    };

    T *data; // Pointer to local memory

  public:
    void init(local T *local_data) {
      data = local_data;
    }

    int getColumnOffset(int columnIndex) {
      columnIndex += BOUNDARY_X;             
      return columnIndex / 2 + (columnIndex & 1) * ODD_OFFSET;  
    }

    T & operator[] (const int index) {
      return data[index];
    }

    template <typename FUNC>
    void horizontalStep(const int count, const int prevOffset, 
                        const int midOffset, const int nextOffset,
                        const FUNC & function) {
      const int STEPS = count / SIZE_X;
      const int finalCount = count % SIZE_X; 
      const int finalOffset = count - finalCount;  

      for(int i = 0; i < STEPS; i++) {
        const T previous = data[prevOffset + i * SIZE_X + get_local_id(0)];
        const T next     = data[nextOffset + i * SIZE_X + get_local_id(0)];
        T & center       = data[midOffset  + i * SIZE_X + get_local_id(0)];
        function(previous, center, next);
      }

      if(get_local_id(0) < finalCount) {
        const T previous = data[prevOffset + finalOffset + get_local_id(0)];
        const T next     = data[nextOffset + finalOffset + get_local_id(0)];
        T & center = data[midOffset + finalOffset + get_local_id(0)];
        function(previous, center, next);
      }
    }

    template <typename FUNC>
    void forEachHorizontalEven(const int firstLine, const int numLines, const FUNC & func) {
      const int count = numLines * VERTICAL_STRIDE - 1;
      const int centerOffset = firstLine * VERTICAL_STRIDE + 1;
      const int prevOffset = firstLine * VERTICAL_STRIDE + ODD_OFFSET;
      const int nextOffset = prevOffset + 1;
      horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename FUNC>
    void forEachHorizontalOdd(const int firstLine, const int numLines, const FUNC & func) {
      const int count = numLines * VERTICAL_STRIDE - 1;
      const int prevOffset = firstLine * VERTICAL_STRIDE;
      const int centerOffset = prevOffset + ODD_OFFSET;
      const int nextOffset = prevOffset + 1;
      horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename F>
    void forEachVerticalEven(const int columnOffset, const F & f) {
      if(SIZE_Y > 3) { 
        const int steps = SIZE_Y / 2 - 1;
        for(int i = 0; i < steps; i++) {
          const int row = 2 + i * 2;
          const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
          const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
          f(prev, data[columnOffset + row * VERTICAL_STRIDE] , next);
        }
      }
    }

    template <typename F>
    void forEachVerticalOdd(const int columnOffset, const F & f) {
      const int steps = (SIZE_Y - 1) / 2;
      for(int i = 0; i < steps; i++) {
        const int row = i * 2 + 1;
        const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
        const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
        f(prev, data[columnOffset + row * VERTICAL_STRIDE], next);
      }
    }

    void scaleHorizontal(const T evenScale, const T oddScale, const int firstLine, const int numLines) {
      const int offset = firstLine * VERTICAL_STRIDE;
      const int count = numLines * VERTICAL_STRIDE;
      const int steps = count / SIZE_X;
      const int finalCount = count % SIZE_X;
      const int finalOffset = count - finalCount;

      for(int i = 0; i < steps; i++) {
        data[get_local_id(0) + i * SIZE_X + offset] *= evenScale;
        data[get_local_id(0) + i * SIZE_X + offset + ODD_OFFSET] *= oddScale;
      }

      if(get_local_id(0) < finalCount) {
        data[get_local_id(0) + finalOffset + offset] *= evenScale;
        data[get_local_id(0) + finalOffset + offset + ODD_OFFSET] *= oddScale;
      }
    }

    void scaleVertical(const T evenScale, const T oddScale, const int columnOffset, const int numLines, const int firstLine) {
      for(int i = firstLine; i < (numLines + firstLine); i++) {
        if(i & 1) {
          data[columnOffset + i * VERTICAL_STRIDE] *= oddScale;
        } else {
          data[columnOffset + i * VERTICAL_STRIDE] *= evenScale;
        }
      }
    }
};

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT53 {
  private:
    template <bool CHECKED_LOADER>
    struct FDWT53Column {
      VerticalDWTPixelLoader<int, CHECKED_LOADER> loader;
      int offset;
      int pixel0, pixel1, pixel2;

      void clear() {
        offset = pixel0 = pixel1 = pixel2 = 0;
        loader.clear();
      }
    };

    typedef TransformBuffer<int, WIN_SIZE_X, WIN_SIZE_Y + 3, 2> FDWT53Buffer;
    FDWT53Buffer buffer;
    enum { STRIDE = FDWT53Buffer::VERTICAL_STRIDE };

    struct Forward53Predict {
      void operator() (const int p, int & c, const int n) const {
        c -= (p + n) / 2;      
      }
    };

    struct Forward53Update {
      void operator() (const int p, int & c, const int n) const {
        c += (p + n + 2) / 4;  
      }
    };

    template <bool CHECKED>
    void initColumn(FDWT53Column<CHECKED> & column, const int * const input,
                    const int sizeX, const int sizeY, const int colIndex, const int firstY) {
      column.offset = buffer.getColumnOffset(colIndex);
      const int firstX = get_group_id(0) * WIN_SIZE_X + colIndex;

      if(get_group_id(1) == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        column.pixel2 = column.loader.loadFrom(input);  
        column.pixel1 = column.loader.loadFrom(input);  
        column.pixel0 = column.loader.loadFrom(input);  
        column.loader.init(sizeX, sizeY, firstX, firstY + 1);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 2);
        column.pixel0 = column.loader.loadFrom(input);
        column.pixel1 = column.loader.loadFrom(input);
        column.pixel2 = column.loader.loadFrom(input);
      }
    }

    template <bool CHECKED>
    void loadAndVerticallyTransform(FDWT53Column<CHECKED> & column, const int * const input) {
      buffer[column.offset + 0 * STRIDE] = column.pixel0;
      buffer[column.offset + 1 * STRIDE] = column.pixel1;
      buffer[column.offset + 2 * STRIDE] = column.pixel2;

      for(int i = 3; i < (3 + WIN_SIZE_Y); i++) 
      {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }

      column.pixel0 = buffer[column.offset + (WIN_SIZE_Y + 0) * STRIDE];
      column.pixel1 = buffer[column.offset + (WIN_SIZE_Y + 1) * STRIDE];
      column.pixel2 = buffer[column.offset + (WIN_SIZE_Y + 2) * STRIDE];

      buffer.forEachVerticalOdd(column.offset, Forward53Predict());
      buffer.forEachVerticalEven(column.offset, Forward53Update());
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const int * const in, int * const out, const int sizeX, const int sizeY, const int winSteps, local int *local_buf) {
      buffer.init(local_buf);

      FDWT53Column<CHECK_LOADS> column;    
      FDWT53Column<CHECK_LOADS> boundaryColumn;  

      const int firstY = get_group_id(1) * WIN_SIZE_Y * winSteps;
      initColumn(column, in, sizeX, sizeY, get_local_id(0), firstY); 

      boundaryColumn.clear();
      if(get_local_id(0) < 3) {
        const int colId = get_local_id(0) + ((get_local_id(0) == 0) ? WIN_SIZE_X : -3);
        initColumn(boundaryColumn, in, sizeX, sizeY, colId, firstY);
      }

      const int outColumnIndex = parityIdx<WIN_SIZE_X>();
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
      const int outputFirstX = get_group_id(0) * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<int, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, outputFirstX, firstY);

      for(int w = 0; w < winSteps; w++) {
        loadAndVerticallyTransform(column, in);
        if(get_local_id(0) < 3) { 
          loadAndVerticallyTransform(boundaryColumn, in); 
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        buffer.forEachHorizontalOdd(2, WIN_SIZE_Y, Forward53Predict());
        barrier(CLK_LOCAL_MEM_FENCE);

        buffer.forEachHorizontalEven(2, WIN_SIZE_Y, Forward53Update());
        barrier(CLK_LOCAL_MEM_FENCE);

        for(int r = 2; r < (2 + WIN_SIZE_Y); r += 2) {
          writer.writeLowInto(out, buffer[outColumnOffset + r * STRIDE]);
          writer.writeHighInto(out, buffer[outColumnOffset + (r+1) * STRIDE]);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
      }
    }

  public:
    static void run(const int * const in, int * const out, const int sx, const int sy, const int steps) {
      const int BUFFER_SIZE = (WIN_SIZE_X / 2 + 2) * (WIN_SIZE_Y + 3);
      const int PADDING = 16 - ((BUFFER_SIZE + 8) % 16);
      const int TOTAL_SIZE = 2 * BUFFER_SIZE + PADDING;

      local int local_buf[TOTAL_SIZE];

      FDWT53<WIN_SIZE_X, WIN_SIZE_Y> fdwt53;
      const int maxX = (get_group_id(0) + 1) * WIN_SIZE_X + 1;
      const int maxY = (get_group_id(1) + 1) * WIN_SIZE_Y * steps + 1;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;

      if(atBottomBoudary) {
        fdwt53.transform<true, true>(in, out, sx, sy, steps, local_buf);
      } else if(atRightBoudary) {
        fdwt53.transform<false, true>(in, out, sx, sy, steps, local_buf);
      } else {
        fdwt53.transform<false, false>(in, out, sx, sy, steps, local_buf);
      }
    }
};

__kernel void cl_fdwt53Kernel(const int * const input, int * const output,
                               const int sizeX, const int sizeY, const int winSteps,
                               const int WIN_SX, const int WIN_SY) {
    FDWT53<WIN_SX, WIN_SY>::run(input, output, sizeX, sizeY, winSteps);
}

template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT97 {
  private:
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> FDWT97Buffer;
    FDWT97Buffer buffer;
    enum { STRIDE = FDWT97Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct FDWT97ColumnLoadingInfo {
      VerticalDWTPixelLoader<float, CHECKED> loader;  
      int offset;
    };

    void horizontalFDWT97(const int lines, const int firstLine) {
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict1));
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update1));
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict2));
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update2));
      barrier(CLK_LOCAL_MEM_FENCE);
      buffer.scaleHorizontal(scale97Div, scale97Mul, firstLine, lines);
      barrier(CLK_LOCAL_MEM_FENCE);
    }

    template <bool CHECKED>
    void initColumn(FDWT97ColumnLoadingInfo<CHECKED> & column, const int columnIndex, 
                    const float * const input, const int sizeX, const int sizeY, const int firstY) {
      column.offset = buffer.getColumnOffset(columnIndex);
      const int firstX = get_group_id(0) * WIN_SIZE_X + columnIndex;

      if(get_group_id(1) == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 3 * STRIDE] = buffer[column.offset + 5 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 2 * STRIDE] = buffer[column.offset + 6 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadFrom(input);
        column.loader.init(sizeX, sizeY, firstX, firstY + 3);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 4);
        for(int i = 0; i < 7; i++) {
          buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const float * const input, FDWT97ColumnLoadingInfo<CHECKED> & column) {
      for(int i = 7; i < (7 + WIN_SIZE_Y); i++) {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const float * const in, float * const out, const int sizeX, const int sizeY, const int winSteps, local float *local_buf) {
      buffer.init(local_buf);

      FDWT97ColumnLoadingInfo<CHECK_LOADS> loadedColumn;
      FDWT97ColumnLoadingInfo<CHECK_LOADS> boundaryColumn;

      const int firstY = get_group_id(1) * WIN_SIZE_Y * winSteps;
      initColumn(loadedColumn, get_local_id(0), in, sizeX, sizeY, firstY);

      boundaryColumn.offset = 0;
      boundaryColumn.loader.clear();
      if(get_local_id(0) < 7) {
        const int colId = get_local_id(0) + ((get_local_id(0) < 3) ? WIN_SIZE_X : -7);
        initColumn(boundaryColumn, colId, in, sizeX, sizeY, firstY);
      }

      horizontalFDWT97(7, 0);

      const int outColumnIndex = parityIdx<WIN_SIZE_X>();
      const int firstX = get_group_id(0) * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<float, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, firstX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);

      for(int w = 0; w < winSteps; w++) {
        loadWindowIntoColumn(in, loadedColumn);
        if(get_local_id(0) < 7) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalFDWT97(WIN_SIZE_Y, 7);

        float last7Lines[7];
        for(int i = 0; i < 7; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }

        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict1));
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update1));
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict2));
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update2));

        for(int i = 4; i < (4 + WIN_SIZE_Y); i += 2) {
          const int index = outColumnOffset + i * STRIDE;
          writer.writeLowInto(out, buffer[index] * scale97Div);
          writer.writeHighInto(out, buffer[index + STRIDE] * scale97Mul);
        }

        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
      }
    }

  public:
    static void run(const float * const input, float * const output, const int sx, const int sy, const int steps) {
      const int BUFFER_SIZE = (WIN_SIZE_X / 2 + 4) * (WIN_SIZE_Y + 7);
      const int PADDING = 16 - ((BUFFER_SIZE + 8) % 16);
      const int TOTAL_SIZE = 2 * BUFFER_SIZE + PADDING;

      local float local_buf[TOTAL_SIZE];

      FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
      const int maxX = (get_group_id(0) + 1) * WIN_SIZE_X + 3;
      const int maxY = (get_group_id(1) + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = maxY >= sy;

      if(atBottomBoudary) {
        fdwt97.transform<true, true>(input, output, sx, sy, steps, local_buf);
      } else if(atRightBoudary) {
        fdwt97.transform<false, true>(input, output, sx, sy, steps, local_buf);
      } else {
