__global__ void c_CopySrcToComponents_float(float *d_r, float *d_g, float *d_b, 
                                  unsigned char * d_src, 
                                  int pixels)
{
    int x  = threadIdx.x;
    int gX = blockDim.x * blockIdx.x;

    __shared__ unsigned char sData[THREADS*3];

    if ( (x*4) < THREADS*3 ) {
        float *s = (float *)d_src;
        float *d = (float *)sData;
        d[x] = s[((gX*3)>>2) + x];
    }
    __syncthreads();

    float r, g, b;

    int offset = x*3;
    r = (float)(sData[offset]);
    g = (float)(sData[offset+1]);
    b = (float)(sData[offset+2]);

    int globalOutputPosition = gX + x;
    if (globalOutputPosition < pixels) {
        storeComponents_float(d_r, d_g, d_b, r, g, b, globalOutputPosition);
    }
}

