    int x  = get_local_id(0);
    int gX = get_local_size(0) * get_group_id(0);

    unsigned char sData[THREADS*3];

    if ( THREADS*3 > (x*4) ) {
        float *s = (float *)d_src;
        float *d = (float *)sData;
        d[x] = s[((gX*3)>>2) + x];
