template <int WIN_SIZE_X, int WIN_SIZE_Y>
class FDWT97 {
private:
    typedef TransformBuffer<float, WIN_SIZE_X, WIN_SIZE_Y + 7, 4> FDWT97Buffer;
    FDWT97Buffer buffer;
    enum { STRIDE = FDWT97Buffer::VERTICAL_STRIDE };

    template <bool CHECKED>
    struct FDWT97ColumnLoadingInfo {
      VerticalDWTPixelLoader<float, CHECKED> loader;  
      int offset;
    };

    void horizontalFDWT97(const int lines, const int firstLine, int threadIdx_x) {
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict1), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update1), threadIdx_x);
      buffer.forEachHorizontalOdd(firstLine, lines, AddScaledSum(f97Predict2), threadIdx_x);
      buffer.forEachHorizontalEven(firstLine, lines, AddScaledSum(f97Update2), threadIdx_x);
      buffer.scaleHorizontal(scale97Div, scale97Mul, firstLine, lines, threadIdx_x);
    }

    template <bool CHECKED>
    void initColumn(FDWT97ColumnLoadingInfo<CHECKED> & column, const int columnIndex, const float * const input, 
                    const int sizeX, const int sizeY, const int firstY, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      column.offset = buffer.getColumnOffset(columnIndex);
      const int firstX = blockIdx_x * WIN_SIZE_X + columnIndex;
      if(blockIdx_y == 0) {
        column.loader.init(sizeX, sizeY, firstX, firstY);
        buffer[column.offset + 4 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 3 * STRIDE] = buffer[column.offset + 5 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 2 * STRIDE] = buffer[column.offset + 6 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 1 * STRIDE] = column.loader.loadFrom(input);
        buffer[column.offset + 0 * STRIDE] = column.loader.loadFrom(input);
        column.loader.init(sizeX, sizeY, firstX, firstY + 3);
      } else {
        column.loader.init(sizeX, sizeY, firstX, firstY - 4);
        for(int i = 0; i < 7; i++) {
          buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
        }
      }
    }

    template <bool CHECKED>
    void loadWindowIntoColumn(const float * const input, FDWT97ColumnLoadingInfo<CHECKED> & column) {
      for(int i = 7; (7 + WIN_SIZE_Y) > i; i++) {
        buffer[column.offset + i * STRIDE] = column.loader.loadFrom(input);
      }
    }

    template <bool CHECK_LOADS, bool CHECK_WRITES>
    void transform(const float * const in, float * const out, const int sizeX, const int sizeY,
                   const int winSteps, int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT97ColumnLoadingInfo<CHECK_LOADS> loadedColumn;
      FDWT97ColumnLoadingInfo<CHECK_LOADS> boundaryColumn;
      const int firstY = blockIdx_y * WIN_SIZE_Y * winSteps;
      initColumn(loadedColumn, threadIdx_x, in, sizeX, sizeY, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      boundaryColumn.offset = 0;
      boundaryColumn.loader.clear();
      if(threadIdx_x < 7) {
        const int colId = threadIdx_x + ((threadIdx_x < 3) ? WIN_SIZE_X : -7);
        initColumn(boundaryColumn, colId, in, sizeX, sizeY, firstY, blockIdx_x, blockIdx_y, threadIdx_x);
      }
      horizontalFDWT97(7, 0, threadIdx_x);
      const int outColumnIndex = parityIdx(WIN_SIZE_X, threadIdx_x);
      const int firstX = blockIdx_x * WIN_SIZE_X + outColumnIndex;
      VerticalDWTBandWriter<float, CHECK_WRITES> writer;
      writer.init(sizeX, sizeY, firstX, firstY);
      const int outColumnOffset = buffer.getColumnOffset(outColumnIndex);
      for(int w = 0; winSteps > w; w++) {
        loadWindowIntoColumn(in, loadedColumn);
        if(threadIdx_x < 7) {
          loadWindowIntoColumn(in, boundaryColumn);
        }
        horizontalFDWT97(WIN_SIZE_Y, 7, threadIdx_x);
        float last7Lines[7];
        for(int i = 0; 7 > i; i++) {
          last7Lines[i] = buffer[outColumnOffset + (WIN_SIZE_Y + i) * STRIDE];
        }
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict1), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update1), threadIdx_x);
        buffer.forEachVerticalOdd(outColumnOffset, AddScaledSum(f97Predict2), threadIdx_x);
        buffer.forEachVerticalEven(outColumnOffset, AddScaledSum(f97Update2), threadIdx_x);
        for(int i = 4; (4 + WIN_SIZE_Y) > i; i += 2) {
          const int index = outColumnOffset + i * STRIDE;
          writer.writeLowInto(out, buffer[index] * scale97Div);
          writer.writeHighInto(out, buffer[index + STRIDE] * scale97Mul);
        }
        for(int i = 0; i < 7; i++) {
          buffer[outColumnOffset + i * STRIDE] = last7Lines[i];
        }
      }
    }
public:
    static void run(const float * const input, float * const output, const int sx, const int sy, const int steps,
                    int blockIdx_x, int blockIdx_y, int threadIdx_x) {
      FDWT97<WIN_SIZE_X, WIN_SIZE_Y> fdwt97;
      const int maxX = (blockIdx_x + 1) * WIN_SIZE_X + 3;
      const int maxY = (blockIdx_y + 1) * WIN_SIZE_Y * steps + 3;
      const bool atRightBoudary = maxX >= sx;
      const bool atBottomBoudary = sy <= maxY;
      if(atBottomBoudary) {
        fdwt97.transform<true, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else if(atRightBoudary) {
        fdwt97.transform<false, true>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      } else {
        fdwt97.transform<false, false>(input, output, sx, sy, steps, blockIdx_x, blockIdx_y, threadIdx_x);
      }
    }
};

