int parityIdx(int THREADS_VAL, int threadIdx_x) {
    return (threadIdx_x * 2) - (THREADS_VAL - 1) * (threadIdx_x / (THREADS_VAL / 2));
}

void mirror(int & d, const int & sizeD) {
    if(d >= sizeD) {
        d = 2 * sizeD - 2 - d;
    } else if(d < 0) {
        d = -d;
    }
}

kernel void cl_fdwt53Kernel(const int * const input, int * const output,
                               const int sizeX, const int sizeY,
                               const int winSteps, const int WIN_SX, const int WIN_SY) {

    int local_x = get_local_id(0);
    int group_x = get_group_id(0);
    int group_y = get_group_id(1);

    int VERTICAL_STRIDE = 2 + (WIN_SX / 2);
    int BUFFER_SIZE = VERTICAL_STRIDE * (WIN_SY + 3);
    int PADDING = 16 - ((BUFFER_SIZE + 8) % 16);
    int ODD_OFFSET = BUFFER_SIZE + PADDING;
    int TOTAL_SIZE = 2 * BUFFER_SIZE + PADDING;

    int buffer[TOTAL_SIZE];

    int firstY = group_y * WIN_SY * winSteps;

    int colIndex = local_x;
    int columnIndex = colIndex + 2;
    int columnOffset = columnIndex / 2 + (columnIndex & 1) * ODD_OFFSET;
    int firstX = group_x * WIN_SX + colIndex;

    int loader_last, loader_stride, loader_end;
    int pixel0, pixel1, pixel2;

    if(group_y == 0) {
        int curX = firstX;
        if(curX >= sizeX) curX = 2*sizeX - 2 - curX; else if(curX < 0) curX = -curX;
        int idx = curX + sizeX * firstY;

        loader_stride = sizeX;
        loader_end = sizeY * sizeX + firstX;
        loader_last = idx - sizeX;

        pixel2 = input[idx]; idx += loader_stride;
        pixel1 = input[idx]; idx += loader_stride;
        pixel0 = input[idx]; idx += loader_stride;

        loader_last = idx - loader_stride;
    } else {
        int curX = firstX;
        if(curX >= sizeX) curX = 2*sizeX - 2 - curX; else if(curX < 0) curX = -curX;
        int idx = curX + sizeX * (firstY - 2);

        loader_stride = sizeX;
        loader_end = sizeY * sizeX + firstX;

        pixel0 = input[idx]; idx += loader_stride;
        pixel1 = input[idx]; idx += loader_stride;
        pixel2 = input[idx]; idx += loader_stride;

        loader_last = idx - loader_stride;
    }

    buffer[columnOffset + 0 * VERTICAL_STRIDE] = pixel0;
    buffer[columnOffset + 1 * VERTICAL_STRIDE] = pixel1;
    buffer[columnOffset + 2 * VERTICAL_STRIDE] = pixel2;

    for(int i = 3; i < (3 + WIN_SY); i++) {
        loader_last += loader_stride;
        if(loader_last == loader_end) { loader_last -= 2*loader_stride; loader_stride = -loader_stride; }
        buffer[columnOffset + i * VERTICAL_STRIDE] = input[loader_last];
    }

    pixel0 = buffer[columnOffset + (WIN_SY + 0) * VERTICAL_STRIDE];
    pixel1 = buffer[columnOffset + (WIN_SY + 1) * VERTICAL_STRIDE];
    pixel2 = buffer[columnOffset + (WIN_SY + 2) * VERTICAL_STRIDE];

    for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
        int row = i * 2 + 1;
        int prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
        int next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
        int center_idx = columnOffset + row * VERTICAL_STRIDE;
        int center = buffer[center_idx];
        center = center - ((prev + next) / 2);
        buffer[center_idx] = center;
    }

    if(WIN_SY > 3) {
        for(int i = 0; i < WIN_SY / 2 - 1; i++) {
            int row = 2 + i * 2;
            int prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
            int next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
            int center_idx = columnOffset + row * VERTICAL_STRIDE;
            int center = buffer[center_idx];
            center = center + ((prev + next + 2) / 4);
            buffer[center_idx] = center;
        }
    }

    int boundaryColumnOffset = 0;
    int b_pixel0 = 0, b_pixel1 = 0, b_pixel2 = 0;
    int b_loader_last, b_loader_stride, b_loader_end;

    if(local_x < 3) {
        int colId = local_x + ((local_x == 0) ? WIN_SX : -3);
        int b_firstX = group_x * WIN_SX + colId;

        int b_curX = b_firstX;
        if(b_curX >= sizeX) b_curX = 2*sizeX - 2 - b_curX; else if(b_curX < 0) b_curX = -b_curX;
        int b_idx = b_curX + sizeX * firstY;

        if(group_y == 0) {
            b_loader_stride = sizeX;
            b_loader_end = sizeY * sizeX + b_firstX;
            b_loader_last = b_idx - sizeX;

            b_pixel2 = input[b_idx]; b_idx += b_loader_stride;
            b_pixel1 = input[b_idx]; b_idx += b_loader_stride;
            b_pixel0 = input[b_idx]; b_idx += b_loader_stride;

            b_loader_last = b_idx - b_loader_stride;
        } else {
            b_loader_stride = sizeX;
            b_loader_end = sizeY * sizeX + b_firstX;
            b_idx = b_curX + sizeX * (firstY - 2);

            b_pixel0 = input[b_idx]; b_idx += b_loader_stride;
            b_pixel1 = input[b_idx]; b_idx += b_loader_stride;
            b_pixel2 = input[b_idx]; b_idx += b_loader_stride;

            b_loader_last = b_idx - b_loader_stride;
        }

        int b_colIndex = colId + 2;
        boundaryColumnOffset = b_colIndex / 2 + (b_colIndex & 1) * ODD_OFFSET;

        buffer[boundaryColumnOffset + 0 * VERTICAL_STRIDE] = b_pixel0;
        buffer[boundaryColumnOffset + 1 * VERTICAL_STRIDE] = b_pixel1;
        buffer[boundaryColumnOffset + 2 * VERTICAL_STRIDE] = b_pixel2;

        for(int i = 3; i < (3 + WIN_SY); i++) {
            b_loader_last += b_loader_stride;
            if(b_loader_last == b_loader_end) { b_loader_last -= 2*b_loader_stride; b_loader_stride = -b_loader_stride; }
            buffer[boundaryColumnOffset + i * VERTICAL_STRIDE] = input[b_loader_last];
        }

        b_pixel0 = buffer[boundaryColumnOffset + (WIN_SY + 0) * VERTICAL_STRIDE];
        b_pixel1 = buffer[boundaryColumnOffset + (WIN_SY + 1) * VERTICAL_STRIDE];
        b_pixel2 = buffer[boundaryColumnOffset + (WIN_SY + 2) * VERTICAL_STRIDE];

        for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
            int row = i * 2 + 1;
            int prev = buffer[boundaryColumnOffset + (row - 1) * VERTICAL_STRIDE];
            int next = buffer[boundaryColumnOffset + (row + 1) * VERTICAL_STRIDE];
            int center_idx = boundaryColumnOffset + row * VERTICAL_STRIDE;
            int center = buffer[center_idx];
            center = center - ((prev + next) / 2);
            buffer[center_idx] = center;
        }

        if(WIN_SY > 3) {
            for(int i = 0; i < WIN_SY / 2 - 1; i++) {
                int row = 2 + i * 2;
                int prev = buffer[boundaryColumnOffset + (row - 1) * VERTICAL_STRIDE];
                int next = buffer[boundaryColumnOffset + (row + 1) * VERTICAL_STRIDE];
                int center_idx = boundaryColumnOffset + row * VERTICAL_STRIDE;
                int center = buffer[center_idx];
                center = center + ((prev + next + 2) / 4);
                buffer[center_idx] = center;
            }
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int count = WIN_SY * VERTICAL_STRIDE - 1;
    int centerOffset = 2 * VERTICAL_STRIDE;
    int prevOffset = ODD_OFFSET;
    int nextOffset = prevOffset + 1;

    int STEPS = count / WIN_SX;
    int finalCount = count % WIN_SX;
    int finalOffset = count - finalCount;

    for(int i = 0; i < STEPS; i++) {
        int previous = buffer[prevOffset + i * WIN_SX + local_x];
        int next = buffer[nextOffset + i * WIN_SX + local_x];
        int center_idx = centerOffset + i * WIN_SX + local_x;
        int center = buffer[center_idx];
        center = center - ((previous + next) / 2);
        buffer[center_idx] = center;
    }
    if(local_x < finalCount) {
        int previous = buffer[prevOffset + finalOffset + local_x];
        int next = buffer[nextOffset + finalOffset + local_x];
        int center_idx = centerOffset + finalOffset + local_x;
        int center = buffer[center_idx];
        center = center - ((previous + next) / 2);
        buffer[center_idx] = center;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    centerOffset = ODD_OFFSET;
    prevOffset = 0;
    nextOffset = 1;

    STEPS = count / WIN_SX;
    finalCount = count % WIN_SX;
    finalOffset = count - finalCount;

    for(int i = 0; i < STEPS; i++) {
        int previous = buffer[prevOffset + i * WIN_SX + local_x];
        int next = buffer[nextOffset + i * WIN_SX + local_x];
        int center_idx = centerOffset + i * WIN_SX + local_x;
        int center = buffer[center_idx];
        center = center + ((previous + next + 2) / 4);
        buffer[center_idx] = center;
    }
    if(local_x < finalCount) {
        int previous = buffer[prevOffset + finalOffset + local_x];
        int next = buffer[nextOffset + finalOffset + local_x];
        int center_idx = centerOffset + finalOffset + local_x;
        int center = buffer[center_idx];
        center = center + ((previous + next + 2) / 4);
        buffer[center_idx] = center;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int outColumnIndex = parityIdx(WIN_SX, local_x);
    int outColumnOffset = outColumnIndex / 2 + ((outColumnIndex + 2) & 1) * ODD_OFFSET; 
    int outputFirstX = group_x * WIN_SX + outColumnIndex;

    int writer_next, writer_end, writer_stride;

    int colOff = outputFirstX / 2;
    int vStride;
    if(outputFirstX & 1) {
        vStride = sizeX / 2;
        colOff += ((sizeX + 1) / 2) * ((sizeY + 1) / 2);
        writer_stride = (sizeX * sizeY) / 2;
    } else {
        vStride = sizeX / 2 + (sizeX & 1);
        writer_stride = ((sizeY + 1) / 2) * sizeX;
    }
    int strideHighToLow = vStride - writer_stride;

    writer_end = 0; 
    writer_next = colOff + (firstY / 2) * vStride + (firstY & 1) * writer_stride;

    for(int w = 0; w < winSteps; w++) {
        if(w > 0 || group_y > 0) { 
             int loadY = firstY + w * WIN_SY * winSteps;
             if(w == 0 && group_y == 0) loadY = firstY + WIN_SY;

             int curX = firstX;
             if(curX >= sizeX) curX = 2*sizeX - 2 - curX; else if(curX < 0) curX = -curX;
             int idx = curX + sizeX * (loadY + WIN_SY);

             int l_last = idx - sizeX;
             int l_stride = sizeX;
             int l_end = sizeY * sizeX + firstX;

             for(int i = 3; i < (3 + WIN_SY); i++) {
                 l_last += l_stride;
                 if(l_last == l_end) { l_last -= 2*l_stride; l_stride = -l_stride; }
                 buffer[columnOffset + i * VERTICAL_STRIDE] = input[l_last];
             }

             pixel0 = buffer[columnOffset + (WIN_SY + 0) * VERTICAL_STRIDE];
             pixel1 = buffer[columnOffset + (WIN_SY + 1) * VERTICAL_STRIDE];
             pixel2 = buffer[columnOffset + (WIN_SY + 2) * VERTICAL_STRIDE];

             for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
                 int row = i * 2 + 1;
                 int prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
                 int next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
                 int center_idx = columnOffset + row * VERTICAL_STRIDE;
                 int center = buffer[center_idx];
                 center = center - ((prev + next) / 2);
                 buffer[center_idx] = center;
             }
             if(WIN_SY > 3) {
                 for(int i = 0; i < WIN_SY / 2 - 1; i++) {
                     int row = 2 + i * 2;
                     int prev = buffer[columnOffset + (row - 1) * VERTICAL_STRIDE];
                     int next = buffer[columnOffset + (row + 1) * VERTICAL_STRIDE];
                     int center_idx = columnOffset + row * VERTICAL_STRIDE;
                     int center = buffer[center_idx];
                     center = center + ((prev + next + 2) / 4);
                     buffer[center_idx] = center;
                 }
             }

             if(local_x < 3) {
                 int colId = local_x + ((local_x == 0) ? WIN_SX : -3);
                 int b_firstX = group_x * WIN_SX + colId;
                 int b_curX = b_firstX;
                 if(b_curX >= sizeX) b_curX = 2*sizeX - 2 - b_curX; else if(b_curX < 0) b_curX = -b_curX;
                 int b_idx = b_curX + sizeX * (loadY + WIN_SY);

                 int b_l_last = b_idx - sizeX;
                 int b_l_stride = sizeX;
                 int b_l_end = sizeY * sizeX + b_firstX;

                 int b_colIndex = colId + 2;
                 int b_offset = b_colIndex / 2 + (b_colIndex & 1) * ODD_OFFSET;

                 for(int i = 3; i < (3 + WIN_SY); i++) {
                     b_l_last += b_l_stride;
                     if(b_l_last == b_l_end) { b_l_last -= 2*b_l_stride; b_l_stride = -b_l_stride; }
                     buffer[b_offset + i * VERTICAL_STRIDE] = input[b_l_last];
                 }

                 b_pixel0 = buffer[b_offset + (WIN_SY + 0) * VERTICAL_STRIDE];
                 b_pixel1 = buffer[b_offset + (WIN_SY + 1) * VERTICAL_STRIDE];
                 b_pixel2 = buffer[b_offset + (WIN_SY + 2) * VERTICAL_STRIDE];

                 for(int i = 0; i < (WIN_SY - 1) / 2; i++) {
                     int row = i * 2 + 1;
                     int prev = buffer[b_offset + (row - 1) * VERTICAL_STRIDE];
                     int next = buffer[b_offset + (row + 1) * VERTICAL_STRIDE];
                     int center_idx = b_offset + row * VERTICAL_STRIDE;
                     int center = buffer[center_idx];
                     center = center - ((prev + next) / 2);
                     buffer[center_idx] = center;
                 }
                 if(WIN_SY > 3) {
                     for(int i = 0; i < WIN_SY / 2 - 1; i++) {
                         int row = 2 + i * 2;
                         int prev = buffer[b_offset + (row - 1) * VERTICAL_STRIDE];
                         int next = buffer[b_offset + (row + 1) * VERTICAL_STRIDE];
                         int center_idx = b_offset + row * VERTICAL_STRIDE;
                         int center = buffer[center_idx];
                         center = center + ((prev + next + 2) / 4);
                         buffer[center_idx] = center;
                     }
                 }
             }

             barrier(CLK_LOCAL_MEM_FENCE);

             count = WIN_SY * VERTICAL_STRIDE - 1;
             centerOffset = 2 * VERTICAL_STRIDE;
             prevOffset = ODD_OFFSET;
             nextOffset = prevOffset + 1;

             STEPS = count / WIN_SX;
             finalCount = count % WIN_SX;
             finalOffset = count - finalCount;

             for(int i = 0; i < STEPS; i++) {
                 int previous = buffer[prevOffset + i * WIN_SX + local_x];
                 int next = buffer[nextOffset + i * WIN_SX + local_x];
                 int center_idx = centerOffset + i * WIN_SX + local_x;
                 int center = buffer[center_idx];
                 center = center - ((previous + next) / 2);
                 buffer[center_idx] = center;
             }
             if(local_x < finalCount) {
                 int previous = buffer[prevOffset + finalOffset + local_x];
                 int next = buffer[nextOffset + finalOffset + local_x];
                 int center_idx = centerOffset + finalOffset + local_x;
                 int center = buffer[center_idx];
                 center = center - ((previous + next) / 2);
                 buffer[center_idx] = center;
             }
             barrier(CLK_LOCAL_MEM_FENCE);

             centerOffset = ODD_OFFSET;
             prevOffset = 0;
             nextOffset = 1;

             STEPS = count / WIN_SX;
             finalCount = count % WIN_SX;
             finalOffset = count - finalCount;

             for(int i = 0; i < STEPS; i++) {
                 int previous = buffer[prevOffset + i * WIN_SX + local_x];
                 int next = buffer[nextOffset + i * WIN_SX + local_x];
                 int center_idx = centerOffset + i * WIN_SX + local_x;
                 int center = buffer[center_idx];
                 center = center + ((previous + next + 2) / 4);
                 buffer[center_idx] = center;
             }
             if(local_x < finalCount) {
                 int previous = buffer[prevOffset + finalOffset + local_x];
                 int next = buffer[nextOffset + finalOffset + local_x];
                 int center_idx = centerOffset + finalOffset + local_x;
                 int center = buffer[center_idx];
                 center = center + ((previous + next + 2) / 4);
                 buffer[center_idx] = center;
             }
             barrier(CLK_LOCAL_MEM_FENCE);
        }

        for(int r = 2; r < (2 + WIN_SY); r += 2) {
            if(writer_next != writer_end) {
                output[writer_next] = buffer[outColumnOffset + r * VERTICAL_STRIDE];
                writer_next += writer_stride;
            }
            if(writer_next != writer_end) {
                output[writer_next] = buffer[outColumnOffset + (r+1) * VERTICAL_STRIDE];
                writer_next += strideHighToLow;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }
