// No special extensions needed for float operations

__kernel void Fan1(float *m_cuda, float *a_cuda, int Size, int t)
{
    int idx = get_global_id(0);
    int limit = Size - 1 - t;

    if (idx >= limit) return;

    int row = idx + t + 1;
    int pivot_idx = Size * t + t;
    int row_idx = Size * row + t;

    float pivot = a_cuda[pivot_idx];
    // Prevent division by zero which might cause undefined behavior on some GPUs
    if (pivot == 0.0f) return; 

    m_cuda[row_idx] = a_cuda[row_idx] / pivot;
}

__kernel void Fan2(float *m_cuda, float *a_cuda, float *b_cuda, int Size, int j1, int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    int x_limit = Size - 1 - t;
    int y_limit = Size - t;

    if (xidx >= x_limit) return;
    if (yidx >= y_limit) return;

    int row = xidx + 1 + t;
    int col = yidx + t;

    int m_idx = Size * row + t;
    int a_row_t_idx = Size * t + col;
    int a_row_col_idx = Size * row + col;

    float m_val = m_cuda[m_idx];
    float a_pivot_col = a_cuda[a_row_t_idx];

    // Update A
    a_cuda[a_row_col_idx] -= m_val * a_pivot_col;

    // Update B (only for the first column of the block, i.e., yidx == 0)
    if (yidx == 0) {
        b_cuda[row] -= m_val * b_cuda[t];
    }
}

// OpenCL C Kernel Code for Gaussian Elimination

__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, int Size, int t)
{   
    int idx = get_global_id(0);
    if(idx >= Size-1-t) return;

    int row = idx + t + 1;
    int col = t;

    m_cuda[Size * row + col] = a_cuda[Size * row + col] / a_cuda[Size * t + t];
}

__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, int Size, int j1, int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    if(xidx >= Size-1-t) return;
    if(yidx >= Size-t) return;

    int row = xidx + 1 + t;
    int col = yidx + t;

    float m_val = m_cuda[Size * row + t];
    float a_diag = a_cuda[Size * t + col];

    a_cuda[Size * row + col] -= m_val * a_diag;

    if(yidx == 0){
        b_cuda[row] -= m_val * b_cuda[t];
    }
}

