void PrintDeviceProperties(){
    cl_platform_id platform;
    cl_device_id device;
    cl_uint numPlatforms;
    cl_uint numDevices;
    cl_int status;

    status = clGetPlatformIDs(1, &platform, &numPlatforms);
    if (status != CL_SUCCESS || numPlatforms == 0) {
        printf("No OpenCL platforms found\n");
        return;
    }

    status = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, &numDevices);
    if (status != CL_SUCCESS || numDevices == 0) {
        printf("No OpenCL devices found\n");
        return;
    }

    char name[256], vendor[256], version[256];
    size_t ret_size;
    cl_ulong mem_size;
    cl_uint max_threads, max_comp_units;
    cl_ulong shared_mem;

    clGetDeviceInfo(device, CL_DEVICE_NAME, sizeof(name), name, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_VENDOR, sizeof(vendor), vendor, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_VERSION, sizeof(version), version, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_GLOBAL_MEM_SIZE, sizeof(mem_size), &mem_size, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_LOCAL_MEM_SIZE, sizeof(shared_mem), &shared_mem, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_MAX_WORK_GROUP_SIZE, sizeof(max_threads), &max_threads, &ret_size);
    clGetDeviceInfo(device, CL_DEVICE_MAX_COMPUTE_UNITS, sizeof(max_comp_units), &max_comp_units, &ret_size);

    printf( "\nDevice Name \t\t - %s ", name );  
    printf( "\n**************************************");  
    printf( "\nTotal Global Memory\t\t\t - %lu KB", (unsigned long)(mem_size/1024) );  
    printf( "\nShared memory available per block \t - %lu KB", (unsigned long)(shared_mem/1024) );  
    printf( "\nMaximum threads per block \t\t - %d", max_threads );  
    printf( "\nNumber of Multi processors \t\t - %d\n\n", max_comp_units );  
    printf( "\nOpenCL ver \t\t\t\t - %s", version );  
}










