    int in_pointer;
    float* d_in2;
    float* d_conv;
    float* d_in2_pad_cumv;
    float* d_in2_pad_cumv_sel;
    float* d_in2_sub_cumh;
    float* d_in2_sub_cumh_sel;
    float* d_in2_sub2;
    float* d_in2_sqr;
