__global__ void
bucketcount( float *input, int *indice, unsigned int *d_prefixoffsets, int size, const float *pivotPoints)
{
	volatile __shared__ unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = blockDim.x * gridDim.x;

	// Initialize shared memory
	for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
		s_offset[i] = 0; 

	__syncthreads(); 

	for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
		float elem = input[tid]; 

		// Binary search for pivot
		int idx  = DIVISIONS/2 - 1; 
		int jump = DIVISIONS/4; 

		// Safe access to pivotPoints
		float piv = pivotPoints[idx]; 

		while(jump >= 1){
			if (elem < piv) {
				idx -= jump;
			} else {
				idx += jump;
			}

			// Clamp idx to valid range [0, DIVISIONS-1]
			if (idx < 0) idx = 0;
			if (idx >= DIVISIONS) idx = DIVISIONS - 1;

			piv = pivotPoints[idx]; 
			jump /= 2; 
		}

		// Final adjustment
		piv = pivotPoints[idx];
		if (elem >= piv) {
			idx++;
		}
		if (idx >= DIVISIONS) idx = DIVISIONS - 1;
		if (idx < 0) idx = 0;

		// Use atomic_add to get a unique offset within the bin
		unsigned int offset = atomic_add(&s_offset[warpBase + idx], 1);

		// Encode index: offset in upper bits, bucket in lower bits
		indice[tid] = (offset << LOG_DIVISIONS) | idx;  
	}

	__syncthreads(); 

	int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY; 

	for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
		d_prefixoffsets[prefixBase + i] = s_offset[i]; 
}

__global__ void bucketprefixoffset(unsigned int *d_prefixoffsets, unsigned int *d_offsets, int blocks) {
	int tid = blockIdx.x * blockDim.x + threadIdx.x; 
	int size = blocks * BUCKET_BLOCK_MEMORY; 
	int sum = 0; 

	// Accumulate sums for each column (division) across blocks
	for (int i = tid; i < size; i += DIVISIONS) {
		int x = d_prefixoffsets[i]; 
		d_prefixoffsets[i] = sum; 
		sum += x; 
	}

	// Store the total sum for this division (thread tid corresponds to division tid if grid is sized correctly)
	// The host launches this with grid.x = DIVISIONS / threads.x
	// So tid here iterates over divisions if we assume 1D mapping
	if (tid < DIVISIONS) {
		d_offsets[tid] = sum; 
	}
