__kernel void mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, float *texData, int *constStartAddr, int *finalStartAddr, int *nullElems) {
    int tid = get_group_id(0) * get_local_size(0) + get_local_id(0);

    int division = tid / threadsPerDiv;
    if (division >= DIVISIONS) return;

    int int_tid = tid - division * threadsPerDiv;
    int Astart = constStartAddr[division] + int_tid * nrElems;
    int Bstart = Astart + nrElems / 2;

    // Check bounds before accessing
    if (Astart >= constStartAddr[division + 1])
        return;

    float4 *resStart = &(result[Astart]);

    if (constStartAddr[division + 1] <= Bstart) {
        int count = constStartAddr[division + 1] - Astart;
        for (int i = 0; i < count; i++) {
            int idx = Astart + i;
            float4 val;
            val.x = texData[idx * 4];
            val.y = texData[idx * 4 + 1];
            val.z = texData[idx * 4 + 2];
            val.w = texData[idx * 4 + 3];
            resStart[i] = val;
        }
        return;
    }

    int aidx = 0;
    int bidx = 0;
    int outidx = 0;
    float4 a, b;

    int idxA = Astart + aidx;
    a.x = texData[idxA * 4];
    a.y = texData[idxA * 4 + 1];
    a.z = texData[idxA * 4 + 2];
    a.w = texData[idxA * 4 + 3];

    int idxB = Bstart + bidx;
    b.x = texData[idxB * 4];
    b.y = texData[idxB * 4 + 1];
    b.z = texData[idxB * 4 + 2];
    b.w = texData[idxB * 4 + 3];

    int limitA = nrElems / 2;
    int limitB = constStartAddr[division + 1] - Bstart;
    if (limitB > nrElems / 2) limitB = nrElems / 2;

    while (true) {
        float4 nextA, nextB;
        bool hasNextA = (aidx + 1 < limitA);
        bool hasNextB = (bidx + 1 < limitB);

        if (hasNextA) {
            int nextIdxA = Astart + aidx + 1;
            nextA.x = texData[nextIdxA * 4];
            nextA.y = texData[nextIdxA * 4 + 1];
            nextA.z = texData[nextIdxA * 4 + 2];
            nextA.w = texData[nextIdxA * 4 + 3];
        }

        if (hasNextB) {
            int nextIdxB = Bstart + bidx + 1;
            nextB.x = texData[nextIdxB * 4];
            nextB.y = texData[nextIdxB * 4 + 1];
            nextB.z = texData[nextIdxB * 4 + 2];
            nextB.w = texData[nextIdxB * 4 + 3];
