    int Bstart = Astart + nrElems/2;

    // Check bounds before accessing result
    if(constStartAddr[division + 1] <= Astart) 
        return; 

    int limit = constStartAddr[division + 1] - Astart;

    if(constStartAddr[division + 1] <= Bstart){
        for(int i=0; i < limit; i++)
        {
            result[Astart + i] = texData[Astart + i]; 
