extern "C"
int kmeansCuda(float  **feature,
           int      nfeatures,
           int      npoints,
           int      nclusters,
           int     *membership,
           float  **clusters,
           int     *new_centers_len,
           float  **new_centers)
{
    int delta = 0;
    int i,j;
    cl_int err;

    clEnqueueWriteBuffer(queue, (cl_mem)membership_d, CL_TRUE, 0, npoints*sizeof(int), membership_new, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, (cl_mem)clusters_d, CL_TRUE, 0, nclusters*nfeatures*sizeof(float), clusters[0], 0, NULL, NULL);

    size_t global_size = num_blocks * num_threads;
    size_t local_size = num_threads;

    clSetKernelArg(kernel_kmeans, 0, sizeof(cl_mem), &feature_d);
    clSetKernelArg(kernel_kmeans, 1, sizeof(int), &nfeatures);
    clSetKernelArg(kernel_kmeans, 2, sizeof(int), &npoints);
    clSetKernelArg(kernel_kmeans, 3, sizeof(int), &nclusters);
    clSetKernelArg(kernel_kmeans, 4, sizeof(cl_mem), &membership_d);
    clSetKernelArg(kernel_kmeans, 5, sizeof(cl_mem), &clusters_d);
    clSetKernelArg(kernel_kmeans, 6, sizeof(cl_mem), &block_clusters_d);
    clSetKernelArg(kernel_kmeans, 7, sizeof(cl_mem), &block_deltas_d);

    clEnqueueTaskKernel(queue, kernel_kmeans, 1, &global_size, &local_size, NULL, NULL);
    clFinish(queue);

    clEnqueueReadBuffer(queue, (cl_mem)membership_d, CL_TRUE, 0, npoints*sizeof(int), membership_new, 0, NULL, NULL);

#ifdef BLOCK_CENTER_REDUCE
    float * block_clusters_h = (float *) malloc(num_blocks * nclusters * nfeatures * sizeof(float));
    clEnqueueReadBuffer(queue, (cl_mem)block_clusters_d, CL_TRUE, 0, num_blocks * nclusters * nfeatures * sizeof(float), block_clusters_h, 0, NULL, NULL);
#endif
#ifdef BLOCK_DELTA_REDUCE
    int * block_deltas_h = (int *) malloc(num_blocks * sizeof(int));
    clEnqueueReadBuffer(queue, (cl_mem)block_deltas_d, CL_TRUE, 0, num_blocks * sizeof(int), block_deltas_h, 0, NULL, NULL);
#endif

    delta = 0;
    for (i = 0; i < npoints; i++)
    {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i])
        {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for (j = 0; j < nfeatures; j)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for(i = 0; i < num_blocks; i++) delta += block_deltas_h[i];
    free(block_deltas_h);
#endif
#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k++) block_new_centers[j*nfeatures + k] = 0.f;
    }
    for(i = 0; i < num_blocks; i++) {
        for(int j = 0; j < nclusters;j++) {
            for(int k = 0; k < nfeatures;k++) {
                block_new_centers[j*nfeatures + k] += block_clusters_h[i * nclusters*nfeatures + j * nfeatures + k];
            }
        }
    }
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k++)
            new_centers[j][k]= block_new_centers[j*nfeatures + k];
    }
    free(block_clusters_h);
#endif

    return delta;
}

