				fp* initvalu_temp,
				fp* finavalu_temp){

	int bx;
	int tx;
	int tid;

	long y_pointer_initial;
	long y_pointer_current;
	long x_pointer_current;
	int err_pointer;
	int scale_pointer;
	int yy_pointer;
	int params_pointer;
	int initvalu_temp_pointer;
	int finavalu_temp_pointer;
	int com_pointer;

	fp err_exponent ;
	fp h_init;
	fp h;
	fp tolerance;
	int xmin;

	int error;
	int outside;
	fp scale_min;
	fp scale_fina;

	int i, j, k;

