    T = Pb + Pt + Pt2 + Pa; kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3); rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
    rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2; rcnCKta = kta*Pt - kat*Ca4CaM*Pa; rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
