    dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN); dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a));
