    context = clCreateContextFromType(ctxprop, CL_DEVICE_TYPE_ALL, NULL, NULL, &err);

    if (!context) {
        printf("ERROR: clCreateContextFromType failed\n");
        return -1;
    }

    result = clGetContextInfo(context, CL_CONTEXT_DEVICES, 0, NULL, &size);
    num_devices = (int) (size / sizeof (cl_device_id));

    if (result != CL_SUCCESS || num_devices < 1) {
        printf("ERROR: clGetContextInfo failed\n");
        return -1;
    }

    device_list = (cl_device_id*) malloc(sizeof(cl_device_id) * num_devices);
    result = clGetContextInfo(context, CL_CONTEXT_DEVICES, size, device_list, NULL);

    size_t max_work_item_sizes[3];
    result = clGetDeviceInfo(device_list[device_id_inuse], CL_DEVICE_MAX_WORK_ITEM_SIZES, sizeof(max_work_item_sizes), (void*)max_work_item_sizes, NULL);
    if (result != CL_SUCCESS) {
        printf("ERROR: clGetDeviceInfo failed\n");
        return -1;
    }

    if (max_work_item_sizes[0] < threads_per_block)
        threads_per_block = max_work_item_sizes[0];

    cmd_queue = clCreateCommandQueue(context, device_list[device_id_inuse], 0, NULL);
    if (!cmd_queue) {
        printf("ERROR: clCreateCommandQueue failed\n");
        return -1;
    }

    return 0;
}

static int shutdown() {
    if (cmd_queue) clReleaseCommandQueue(cmd_queue);
    if (context) clReleaseContext(context);
    if (device_list) free(device_list);
    cmd_queue = 0;
    context = 0;
    device_list = 0;
    num_devices = 0;
    device_type = 0;
    return 0;
}

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

float elapsed_time(long long start_time, long long end_time) {
    return (float) (end_time - start_time) / (1000 * 1000);
}

double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double roundDouble(double value) {
    int newValue = (int) (value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue + 1.0;
}

void setIf(int testValue, int newValue, int * array3D, int * dimX, int * dimY, int * dimZ) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

void addNoise(int * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] = array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(int * matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;
    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(int * matrix, int dimX, int dimY, int dimZ, int error, int * newMatrix) {
    int x, y, z;
    for (z = 0; z < dimZ; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int * se, int numOnes, double * neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(int * I, int IszX, int IszY, int Nfr, int * seed) {
    int k;
    int max_size = IszX * IszY * Nfr;
    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size) pos = 0;
        I[pos] = 1;
    }

    int * newMatrix = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

double calcLikelihoodSum(int * I, int * ind, int numOnes) {
    double likelihoodSum = 0.0;
    int y;
    for (y = 0; y < numOnes; y++)
        likelihoodSum += (pow((double)(I[ind[y]] - 100), 2) - pow((double)(I[ind[y]] - 228), 2)) / 50.0;
    return likelihoodSum;
}

int findIndex(double * CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) return lengthCDF - 1;
    return index;
}

void particleFilter(int * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time();

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1) countOnes++;
        }
    }
    double * objxy = (double *)malloc(countOnes * 2 * sizeof(double));
    getneighbors(disk, countOnes, objxy, radius);

    long long get_neighbors = get_time();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time(start, get_neighbors));

    double * weights = (double *)malloc(sizeof(double) * Nparticles);
    for (x = 0; x < Nparticles; x++) weights[x] = 1.0 / ((double)(Nparticles));

    long long get_weights = get_time();
    printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time(get_neighbors, get_weights));

    double * likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double * xj = (double *)malloc(sizeof(double) * Nparticles);
    double * yj = (double *)malloc(sizeof(double) * Nparticles);
    double * CDF = (double *)malloc(sizeof(double) * Nparticles);

    cl_mem arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, CDF_GPU, u_GPU;
    int * ind = (int*)malloc(sizeof(int) * countOnes);
    double * u = (double *)malloc(sizeof(double) * Nparticles);

    if (initialize()) return;

    cl_int err = 0;
    const char * tempchar = "./translated_1.cl";
    FILE * fp = fopen(tempchar, "rb");
    if (!fp) {
        printf("ERROR: unable to open '%s'\n", tempchar);
        return;
    }

    size_t source_size;
    char * source = NULL;
    fseek(fp, 0, SEEK_END);
    source_size = ftell(fp);
    fseek(fp, 0, SEEK_SET);
    source = (char *)malloc(source_size + 1);
    fread(source, 1, source_size, fp);
    fclose(fp);

    cl_program prog = clCreateProgramWithSource(context, 1, &source, &source_size, &err);
    free(source);

    err = clBuildProgram(prog, 1, &device_list[device_id_inuse], "-cl-fast-relaxed-math", NULL, NULL);
    if (err != CL_SUCCESS) {
        printf("ERROR: clBuildProgram => %d\n", err);
        return;
    }

    cl_kernel kernel_find_index = clCreateKernel(prog, "kernel", &err);
    if (err != CL_SUCCESS) {
        printf("ERROR: clCreateKernel => %d\n", err);
        return;
    }

    arrayX_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);
    arrayY_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);
    xj_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);
    yj_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);
    CDF_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);
    u_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double) * Nparticles, NULL, &err);

    for (x = 0; x < Nparticles; x++) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }

    int k;
    int indX, indY;

    for (k = 1; k < Nfr; k++) {
        long long set_arrays = get_time();

        for (x = 0; x < Nparticles; x++) {
            arrayX[x] = arrayX[x] + 1.0 + 5.0 * randn(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0 * randn(seed, x);
        }

        long long error_time = get_time();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(set_arrays, error_time));

        for (x = 0; x < Nparticles; x++) {
            for (y = 0; y < countOnes; y++) {
                indX = roundDouble(arrayX[x]) + objxy[y * 2 + 1];
                indY = roundDouble(arrayY[x]) + objxy[y * 2];
                ind[y] = fabs(indX * IszY * Nfr + indY * Nfr + k);
                if (ind[y] >= max_size) ind[y] = 0;
            }
            likelihood[x] = calcLikelihoodSum(I, ind, countOnes);
            likelihood[x] = likelihood[x] / countOnes;
        }

        long long likelihood_time = get_time();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error_time, likelihood_time));

        for (x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] * exp(likelihood[x]);
        }

        long long exponential_time = get_time();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential_time));

        double sumWeights = 0;
        for (x = 0; x < Nparticles; x++) sumWeights += weights[x];

        long long sum_time = get_time();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential_time, sum_time));

        for (x = 0; x < Nparticles; x++) weights[x] = weights[x] / sumWeights;

        long long normalize_time = get_time();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize_time));

        xe = 0; ye = 0;
        for (x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
        }

        long long move_time = get_time();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize_time, move_time));
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) + pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        CDF[0] = weights[0];
        for (x = 1; x < Nparticles; x++) CDF[x] = weights[x] + CDF[x - 1];

        long long cum_sum_time = get_time();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum_time));

        double u1 = (1.0 / ((double)(Nparticles))) * randu(seed, 0);
        for (x = 0; x < Nparticles; x++) u[x] = u1 + x / ((double)(Nparticles));

        long long u_time = get_time();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum_time, u_time));

        long long start_copy = get_time();
        clEnqueueWriteBuffer(cmd_queue, arrayX_GPU, 1, 0, sizeof(double) * Nparticles, arrayX, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, arrayY_GPU, 1, 0, sizeof(double) * Nparticles, arrayY, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, xj_GPU, 1, 0, sizeof(double) * Nparticles, xj, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, yj_GPU, 1, 0, sizeof(double) * Nparticles, yj, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, CDF_GPU, 1, 0, sizeof(double) * Nparticles, CDF, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, u_GPU, 1, 0, sizeof(double) * Nparticles, u, 0, 0, NULL);
        clFinish(cmd_queue);
        long long end_copy = get_time();

        int num_blocks = ceil((double) Nparticles / (double) threads_per_block);
        size_t local_work[3] = {threads_per_block, 1, 1};
        size_t global_work[3] = {num_blocks * threads_per_block, 1, 1};

        clSetKernelArg(kernel_find_index, 0, sizeof(cl_mem), &arrayX_GPU);
        clSetKernelArg(kernel_find_index, 1, sizeof(cl_mem), &arrayY_GPU);
        clSetKernelArg(kernel_find_index, 2, sizeof(cl_mem), &CDF_GPU);
        clSetKernelArg(kernel_find_index, 3, sizeof(cl_mem), &u_GPU);
        clSetKernelArg(kernel_find_index, 4, sizeof(cl_mem), &xj_GPU);
        clSetKernelArg(kernel_find_index, 5, sizeof(cl_mem), &yj_GPU);
        clSetKernelArg(kernel_find_index, 6, sizeof(cl_int), &Nparticles);

        clEnqueueNDRangeKernel(cmd_queue, kernel_find_index, 1, NULL, global_work, local_work, 0, 0, NULL);
        clFinish(cmd_queue);

        long long start_copy_back = get_time();
        clEnqueueReadBuffer(cmd_queue, yj_GPU, 1, 0, sizeof(double) * Nparticles, yj, 0, 0, NULL);
        clEnqueueReadBuffer(cmd_queue, xj_GPU, 1, 0, sizeof(double) * Nparticles, xj, 0, 0, NULL);
        clFinish(cmd_queue);
        long long end_copy_back = get_time();

        printf("SENDING TO GPU TOOK: %lf\n", elapsed_time(start_copy, end_copy));
        printf("CUDA EXEC TOOK: %lf\n", elapsed_time(end_copy, start_copy_back));
        printf("SENDING BACK FROM GPU TOOK: %lf\n", elapsed_time(start_copy_back, end_copy_back));

        long long xyj_time = get_time();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

        for (x = 0; x < Nparticles; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1.0 / ((double)(Nparticles));
        }

        long long reset_time = get_time();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset_time));
    }

    clReleaseMemObject(u_GPU);
    clReleaseMemObject(CDF_GPU);
    clReleaseMemObject(yj_GPU);
    clReleaseMemObject(xj_GPU);
    clReleaseMemObject(arrayY_GPU);
    clReleaseMemObject(arrayX_GPU);
    clReleaseKernel(kernel_find_index);
    clReleaseProgram(prog);
    shutdown();

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(u);
    free(ind);
}

int main(int argc, char * argv[]) {
    char* usage = "naive.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc) sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc) sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default: break;
        }
    }

    int * seed = (int *)malloc(sizeof(int) * Nparticles);
    int i;
    for (i = 0; i < Nparticles; i++) seed[i] = time(0) * i;

    int * I = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    long long start = get_time();

    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

