#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932

double calcLikelihoodSum(unsigned char * I, int * ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for (x = 0; numOnes > x; x++)
        likelihoodSum = likelihoodSum + ((pow((double) (I[ind[index * numOnes + x]] - 100), 2) - pow((double) (I[ind[index * numOnes + x]] - 228), 2)) / 50.0);
    return likelihoodSum;
}

void cdfCalc(double * CDF, double * weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for (x = 1; Nparticles > x; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

double d_randu(int * seed, int index) {
    int M = 2147483647;
    int A = 1103515245;
    int C = 12345;
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double d_randn(int * seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double updateWeights(double * weights, double * likelihood, int Nparticles) {
    int x;
    double sum = 0;
    for (x = 0; Nparticles > x; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum = sum + (weights[x]);
    }
    return sum;
}

int findIndexBin(double * CDF, int beginIndex, int endIndex, double value) {
    if (beginIndex > endIndex)
        return -1;
    int middleIndex;
    while (beginIndex < endIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (value <= CDF[middleIndex]) {
            if (0 == middleIndex)
                return middleIndex;
            else if (value > CDF[middleIndex - 1])
                return middleIndex;
            else if (value == CDF[middleIndex - 1]) {
                while (value == CDF[middleIndex] && 0 <= middleIndex)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (value < CDF[middleIndex])
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

double dev_round_double(double value) {
    int newValue = (int) (value);
    if (.5f > value - newValue)
        return newValue;
    else
        return newValue + 1.0;
}

void find_index_kernel(double * arrayX, double * arrayY, double * CDF, double * u, double * xj, double * yj, double * weights, int Nparticles) {
    int block_id = blockIdx.x;
    int i = blockDim.x * block_id + threadIdx.x;

    if (Nparticles > i) {
        int index = -1;
        int x;

        for (x = 0; Nparticles > x; x++) {
            if (u[i] <= CDF[x]) {
                index = x;
                break;
            }
        }
        if (-1 == index) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void normalize_weights_kernel(double * weights, int Nparticles, double* partial_sums, double * CDF, double * u, int * seed) {
    int block_id = blockIdx.x;
    int i = blockDim.x * block_id + threadIdx.x;
    __shared__ double u1, sumWeights;

    if(0 == threadIdx.x)
        sumWeights = partial_sums[0];

    __syncthreads();

    if (Nparticles > i) {
        weights[i] = weights[i] / sumWeights;
    }

    __syncthreads(); 

    if (0 == i) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1 / ((double) (Nparticles))) * d_randu(seed, i); 
    }

    __syncthreads();

    if(0 == threadIdx.x) 
        u1 = u[0];

    __syncthreads();

    if (Nparticles > i) {
        u[i] = u1 + i / ((double) (Nparticles));
    }
}

void sum_kernel(double* partial_sums, int Nparticles) {
    int block_id = blockIdx.x;
    int i = blockDim.x * block_id + threadIdx.x;

    if (0 == i) {
        int x;
        double sum = 0.0;
        int num_blocks = ceil((double) Nparticles / 512.0);
        for (x = 0; num_blocks > x; x++) {
            sum = sum + (partial_sums[x]);
        }
        partial_sums[0] = sum;
    }
}

void likelihood_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * CDF, int * ind, int * objxy, double * likelihood, unsigned char * I, double * u, double * weights, int Nparticles, int countOnes, int max_size, int k, int IszY, int Nfr, int *seed, double* partial_sums) {
    int block_id = blockIdx.x;
