    if (Nparticles > i) {
        buffer[threadIdx.x] = weights[i];
    }

    __syncthreads();

    for (unsigned int s = blockDim.x / 2; 0 < s; s >>= 1) {
        if (threadIdx.x < s) {
            buffer[threadIdx.x] += buffer[threadIdx.x + s];
        }
        __syncthreads();
    }
    if (threadIdx.x == 0) {
        partial_sums[blockIdx.x] = buffer[0];
    }

