    double * arrayX = (double *)malloc(sizeof(double)*Nparticles);
    double * arrayY = (double *)malloc(sizeof(double)*Nparticles);
    double * xj = (double *)malloc(sizeof(double)*Nparticles);
    double * yj = (double *)malloc(sizeof(double)*Nparticles);
    double * CDF = (double *)malloc(sizeof(double)*Nparticles);

    cl_mem arrayX_GPU;
    cl_mem arrayY_GPU;
    cl_mem xj_GPU;
    cl_mem yj_GPU;
    cl_mem CDF_GPU;
    double * u = (double *)malloc(sizeof(double)*Nparticles);
    cl_mem u_GPU;

    cl_int err = 0;
    arrayX_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);
    arrayY_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);
    xj_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);
    yj_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);
    CDF_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);
    u_GPU = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(double)*Nparticles, NULL, &err);
    check_error(err);

    for(x = 0; Nparticles > x; x++){
        arrayX[x] = xe;
        arrayY[x] = ye;
    }
    int k;
    int indX, indY;

    int sourcesize = 2048 * 2048;
    char * source = (char *) calloc(sourcesize, sizeof (char));
    const char * tempchar = "./particle_naive.cl";
    FILE * fp = fopen(tempchar, "rb");
    if (!fp) {
        printf("ERROR: unable to open '%s'\n", tempchar);
        return;
    }
    fread(source, sourcesize, 1, fp);
    fclose(fp);

    cl_program prog = clCreateProgramWithSource(context, 1, (const char**)&source, NULL, &err);
    check_error(err);
    err = clBuildProgram(prog, 1, &device_list[device_id_inuse], "-cl-fast-relaxed-math", NULL, NULL);
    if (err != CL_SUCCESS) {
        printf("ERROR: clBuildProgram() => %d\n", err);
        return;
    }

    cl_kernel kernel_obj = clCreateKernel(prog, "kernel", &err);
    check_error(err);

    for(k = 1; Nfr > k; k++){
        long long set_arrays = get_time();

        for(x = 0; Nparticles > x; x++){
            arrayX[x] = arrayX[x] + 1.0 + 5.0*randn(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0*randn(seed, x);
        }

        long long error_time = get_time();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time(set_arrays, error_time));

        int * ind_local = (int*)malloc(sizeof(int)*countOnes);
        for(x = 0; Nparticles > x; x++){
            for(y = 0; countOnes > y; y++){
                indX = roundDouble(arrayX[x]) + objxy[y*2 + 1];
                indY = roundDouble(arrayY[x]) + objxy[y*2];
                int idx_val = fabs(indX*IszY*Nfr + indY*Nfr + k);
                if(max_size <= idx_val) idx_val = 0;
                ind_local[y] = idx_val;
            }
            likelihood[x] = calcLikelihoodSum(I, ind_local, countOnes);
            likelihood[x] = likelihood[x]/countOnes;
        }
        free(ind_local);

        long long likelihood_time = get_time();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time(error_time, likelihood_time));

        for(x = 0; Nparticles > x; x++){
            weights[x] = weights[x] * exp(likelihood[x]);
        }
        long long exponential = get_time();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time(likelihood_time, exponential));
        double sumWeights = 0;	
        for(x = 0; Nparticles > x; x++){
            sumWeights = sumWeights + (weights[x]);
        }
        long long sum_time = get_time();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time(exponential, sum_time));
        for(x = 0; Nparticles > x; x++){
            weights[x] = weights[x]/sumWeights;
        }
        long long normalize = get_time();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time(sum_time, normalize));
        xe = 0;
        ye = 0;

        for(x = 0; Nparticles > x; x++){
            xe = xe + (arrayX[x] * weights[x]);
            ye = ye + (arrayY[x] * weights[x]);
        }
        long long move_time = get_time();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time(normalize, move_time));
        printf("XE: %lf\n", xe);
