  float cost;  
} Point_Struct;

static float d_dist(int p1, int p2, int num, int dim, const float *coord_d)
{
	float retval = 0.0;
	for(int i = 0; i < dim; i++){
		float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

__kernel void
kernel_compute_cost(int num, int dim, long x, const Point_Struct *p, int K, int stride,
					const float *coord_d, float *work_mem_d, const int *center_table_d, char *switch_membership_d)
{
	int bid = get_block_id(0);
	int grid_dim_x = get_num_blocks(0);
	int grid_dim_y = get_num_blocks(1);

	if (grid_dim_y > 0) {
		bid += grid_dim_x * get_block_id(1);
	}

	int tid = get_block_size(0) * bid + get_local_id(0);

	if(tid < num)
	{
		float *lower = &work_mem_d[tid*stride];

		float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

		if ( x_cost < p[tid].cost )
		{
			switch_membership_d[tid] = 1;
			lower[K] += x_cost - p[tid].cost;
		}
		else
		{
			lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
		}
	}
}

