		    if ( low > 0 ) {
				numclose++;				
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost += work_mem_h[i*stride+K];
	}



	if ( gl_cost < 0 ) {
		for(int i=0; i<num; i++){

			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
		    if ( (switch_membership[i]=='1') || close_center ) {
